-- ===========================================================================
-- 002_role_bootstrap.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — runtime role bootstrap.
--
-- Grants the non-superuser runtime role (`sng_app`) the minimum
-- privileges the control-plane needs on the public schema:
--
--   * USAGE on the schema itself,
--   * SELECT/INSERT/UPDATE/DELETE on every table created by 001
--     (and any future migration — see ALTER DEFAULT PRIVILEGES
--     block at the bottom),
--   * USAGE on every sequence (so DEFAULT uuid_generate_v4() and
--     any future SERIAL columns work under `SET ROLE sng_app`).
--
-- The role itself is intentionally NOT created here. SNG's
-- deployment model treats role lifecycle as an operator concern,
-- not a schema concern:
--
--   * Production: a deploy admin pre-provisions `sng_app` once,
--     scoped by the org's IAM / database-access policy. The role
--     outlives any single migration cycle.
--   * Integration tests: the test harness creates an ephemeral
--     `sng_app` role inside each testcontainers postgres instance
--     before invoking the migration runner.
--
-- Both paths converge here: once `sng_app` exists, *this*
-- migration is the single source of truth for what `sng_app` can
-- and cannot do on the schema. See `docs/deploy.md` for the
-- runbook.
--
-- ROW LEVEL SECURITY. Tenant-scoped tables created by 001 enable
-- and FORCE row level security. `FORCE ROW LEVEL SECURITY` does
-- NOT apply to superusers (so the migration runner — typically a
-- superuser — bypasses RLS), but it DOES apply to `sng_app`. This
-- migration grants the DML privileges that let RLS *kick in*; it
-- does not weaken the policies themselves.

-- ---------------------------------------------------------------------
-- Fail loudly if `sng_app` is not provisioned.
--
-- Without this guard, every GRANT below would error out with the
-- somewhat opaque `role "sng_app" does not exist`. The DO block
-- surfaces the real remediation (see docs/deploy.md) instead.
-- ---------------------------------------------------------------------
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'sng_app') THEN
        RAISE EXCEPTION USING
            ERRCODE = 'undefined_object',
            MESSAGE = 'sng_app role missing; provision it before running migrations (see docs/deploy.md)',
            HINT    = 'CREATE ROLE sng_app NOLOGIN; GRANT sng_app TO <migration_runner>;';
    END IF;
END $$;

-- ---------------------------------------------------------------------
-- Schema-level USAGE.
--
-- Without USAGE on `public`, `sng_app` cannot resolve any object
-- name in the schema regardless of table-level grants. Idempotent:
-- re-granting USAGE on an already-granted schema is a no-op.
-- ---------------------------------------------------------------------
GRANT USAGE ON SCHEMA public TO sng_app;

-- ---------------------------------------------------------------------
-- DML on every existing table.
--
-- Covers every table created by 001 (tenants, sites, users, roles,
-- user_roles, devices, claim_tokens, audit_log, policy_graphs,
-- policy_bundles). The blanket `ON ALL TABLES IN SCHEMA public`
-- form is intentional — explicit per-table grants would drift
-- silently as new migrations add tables, which was the exact
-- failure mode this migration is meant to close.
--
-- TRUNCATE / REFERENCES are NOT granted: the runtime role should
-- never bulk-wipe a table (use a `sng_admin` role for destructive
-- ops) and FK creation is a schema-time operation owned by the
-- migration runner, not the runtime role.
-- ---------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO sng_app;

-- ---------------------------------------------------------------------
-- USAGE on sequences.
--
-- Several columns default to `uuid_generate_v4()` (no sequence),
-- but `policy_graphs.version`, `audit_log` ingestion counters, and
-- any future SERIAL/BIGSERIAL columns rely on sequences. USAGE
-- covers nextval/currval/setval which a runtime DML role needs.
-- ---------------------------------------------------------------------
GRANT USAGE ON ALL SEQUENCES IN SCHEMA public TO sng_app;

-- ---------------------------------------------------------------------
-- Default privileges for future objects.
--
-- `ALTER DEFAULT PRIVILEGES` only applies to objects created AFTER
-- the statement is executed, BY the role that ran the statement.
-- Inside a migration this works because every future migration
-- also runs as the same migration runner (the role that owns the
-- default-privileges entry). Re-running this block is a no-op —
-- Postgres treats identical default-privilege rows as a single
-- entry.
--
-- This is what lets later migrations (003, 004, ...) add tables
-- WITHOUT needing to repeat the GRANT clauses: the runtime role
-- inherits DML automatically.
-- ---------------------------------------------------------------------
ALTER DEFAULT PRIVILEGES IN SCHEMA public
    GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO sng_app;
ALTER DEFAULT PRIVILEGES IN SCHEMA public
    GRANT USAGE ON SEQUENCES TO sng_app;

-- ===========================================================================
-- 003_webhooks.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — webhooks migration.
--
-- Adds two tables:
--   - webhook_endpoints  : per-tenant subscriptions (URL + event filter + signing secret).
--   - webhook_deliveries : append-only delivery attempts (status + retry metadata).
--
-- Both tables are RLS-scoped to `sng.tenant_id`. webhook_deliveries
-- joins to webhook_endpoints for tenant lookup so the RLS policy
-- can be written without a redundant `tenant_id` column.
-- However, we still carry a denormalised tenant_id on deliveries to
-- keep the policy simple and avoid recursive policy evaluation
-- (Postgres RLS recursion is allowed but expensive). The
-- denormalised column is enforced consistent by a trigger.

-- signing_secret stores the plaintext HMAC-SHA256 signing key
-- required by the delivery worker at request-signing time. The
-- receiver verifies signatures with the same plaintext, which is
-- emitted exactly once on POST /webhooks (Create). At-rest
-- protection is an ops concern handled by disk encryption / DB
-- TDE; future iterations can layer pgcrypto sym_encrypt with a
-- KEK without changing the column shape.
CREATE TABLE IF NOT EXISTS webhook_endpoints (
    id              UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id       UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    url             TEXT        NOT NULL,
    events          TEXT[]      NOT NULL,
    signing_secret  BYTEA       NOT NULL,
    status          TEXT        NOT NULL DEFAULT 'active'
                    CHECK (status IN ('active', 'disabled')),
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_webhook_endpoints_tenant
    ON webhook_endpoints (tenant_id);
CREATE INDEX IF NOT EXISTS idx_webhook_endpoints_tenant_status
    ON webhook_endpoints (tenant_id, status);

CREATE TRIGGER webhook_endpoints_set_updated_at
    BEFORE UPDATE ON webhook_endpoints
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE webhook_endpoints ENABLE ROW LEVEL SECURITY;
ALTER TABLE webhook_endpoints FORCE ROW LEVEL SECURITY;

CREATE POLICY webhook_endpoints_tenant_isolation ON webhook_endpoints
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid)
    WITH CHECK (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

CREATE TABLE IF NOT EXISTS webhook_deliveries (
    id              UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id       UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    endpoint_id     UUID        NOT NULL REFERENCES webhook_endpoints(id) ON DELETE CASCADE,
    event_type      TEXT        NOT NULL,
    payload         JSONB       NOT NULL,
    status          TEXT        NOT NULL DEFAULT 'pending'
                    CHECK (status IN ('pending', 'delivered', 'failed', 'exhausted')),
    attempts        INTEGER     NOT NULL DEFAULT 0,
    last_attempt_at TIMESTAMPTZ,
    last_error      TEXT,
    next_retry_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    response_status INTEGER,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_tenant
    ON webhook_deliveries (tenant_id);
CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_pending_next
    ON webhook_deliveries (status, next_retry_at)
    WHERE status = 'pending';
CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_endpoint
    ON webhook_deliveries (endpoint_id);

ALTER TABLE webhook_deliveries ENABLE ROW LEVEL SECURITY;
ALTER TABLE webhook_deliveries FORCE ROW LEVEL SECURITY;

-- Tenant-scoped per-request access, plus a system-role bypass so
-- the cross-tenant delivery worker can drain pending rows via
-- `sng.system_role='true'`. The system role can only be set by the
-- application (it's a GUC, not a DB role grant) — RLS still
-- enforces per-tenant isolation for normal handlers.
CREATE POLICY webhook_deliveries_tenant_isolation ON webhook_deliveries
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    )
    WITH CHECK (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    );

-- ===========================================================================
-- 004_webhook_processing.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — webhook delivery atomic-claim migration.
--
-- Background. Migration 002 modelled webhook_deliveries.status with
-- four states: pending → delivered | failed | exhausted. The
-- delivery worker drained pending rows via a SELECT ... FOR UPDATE
-- SKIP LOCKED in `ListPending`, then released the lock by
-- committing the transaction *before* the worker processed each
-- row (the worker iterates over the returned slice and calls
-- UpdateStatus for each delivery). The SKIP LOCKED hint is
-- therefore ineffective: the moment the SELECT transaction commits,
-- the locks are released and a second worker (or even the same
-- worker on a subsequent tick) can fetch the same rows again,
-- producing duplicate HTTP POSTs to subscribers.
--
-- Fix. Add an explicit `processing` state and turn ListPending into
-- an atomic claim: `UPDATE ... SET status='processing' WHERE ...
-- RETURNING ...`. Worker observes a row in 'processing' state and
-- knows it owns the delivery exclusively. On success the worker
-- transitions processing → delivered; on transient failure
-- processing → pending (with next_retry_at advanced); on terminal
-- failure processing → exhausted. A crashed worker leaves rows
-- stuck in 'processing'; the next call to ListPending re-claims any
-- row whose last_attempt_at is older than a configurable
-- processing-timeout window (default 5 minutes), bounding worst-case
-- delivery delay to that window without ever double-delivering
-- within it.
--
-- This migration is additive — existing 'pending' / 'delivered' /
-- 'failed' / 'exhausted' rows are untouched; only the CHECK
-- constraint is widened to admit 'processing'. The partial index
-- previously WHERE status='pending' is replaced with one covering
-- both pending and processing rows so the atomic-claim query stays
-- index-driven.

ALTER TABLE webhook_deliveries
    DROP CONSTRAINT IF EXISTS webhook_deliveries_status_check;

ALTER TABLE webhook_deliveries
    ADD CONSTRAINT webhook_deliveries_status_check
        CHECK (status IN ('pending', 'processing', 'delivered', 'failed', 'exhausted'));

DROP INDEX IF EXISTS idx_webhook_deliveries_pending_next;

-- Composite index optimised for the atomic-claim query. The
-- (status, next_retry_at) order is intentional: the WHERE clause
-- always filters on status first and then orders by next_retry_at,
-- so a btree on these columns is index-only-scan friendly. The
-- predicate is widened to include both 'pending' and 'processing'
-- so the same index serves both the normal-claim and the stuck-row
-- reaper paths.
CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_claimable
    ON webhook_deliveries (status, next_retry_at)
    WHERE status IN ('pending', 'processing');

-- ===========================================================================
-- 005_policy_signing_keys.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — per-tenant Ed25519 signing key store.
--
-- Each tenant owns a set of Ed25519 signing keys used to sign
-- compiled policy bundles. Exactly one key per tenant is active at
-- any time (enforced by a partial unique index); the others are
-- rotated or revoked. Receivers verify a bundle by fetching the
-- public key whose `key_id` matches the `kid` field in the bundle
-- envelope.
--
-- Private-key storage: The raw Ed25519 seed (32 bytes) is stored in
-- the `private_key` column as BYTEA.  At-rest protection is
-- delegated to disk encryption / TDE, same as the
-- `webhook_endpoints.signing_secret` column (see 002_webhooks.up.sql
-- for the rationale). PR8 will introduce an optional KMS-wrapping
-- layer that replaces the plaintext seed with a KMS ciphertext blob.

CREATE TABLE policy_signing_keys (
    id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id     UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    key_id        TEXT NOT NULL,
    algorithm     TEXT NOT NULL CHECK (algorithm IN ('ed25519')),
    public_key    BYTEA NOT NULL,
    private_key   BYTEA NOT NULL,
    status        TEXT NOT NULL CHECK (status IN ('active', 'rotated', 'revoked')),
    activated_at  TIMESTAMPTZ NOT NULL,
    rotated_at    TIMESTAMPTZ,
    revoked_at    TIMESTAMPTZ,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (tenant_id, key_id)
);

-- At most one active key per tenant. The partial unique index
-- makes concurrent rotation safe: the INSERT of the new active key
-- and the UPDATE of the old key's status to 'rotated' can happen
-- in the same transaction, and any interleaving that would create
-- two active keys is rejected by the constraint. This index also
-- serves as the fast-lookup path for the active-key probe; a
-- separate non-unique partial index with the same (tenant_id) +
-- WHERE clause would be fully redundant (Devin Review
-- #3312780989: write amplification with zero query benefit), so
-- we deliberately use only this one.
CREATE UNIQUE INDEX policy_signing_keys_tenant_one_active_idx
    ON policy_signing_keys (tenant_id)
    WHERE status = 'active';

ALTER TABLE policy_signing_keys ENABLE ROW LEVEL SECURITY;
ALTER TABLE policy_signing_keys FORCE ROW LEVEL SECURITY;
CREATE POLICY policy_signing_keys_tenant_isolation ON policy_signing_keys
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

-- Widen policy_bundles with a key_id column so receivers know which
-- public key to verify the signature against. Existing rows get a
-- NULL key_id (pre-rotation bundles signed with the ephemeral signer
-- from PR6). New rows will always carry a non-NULL key_id.
ALTER TABLE policy_bundles ADD COLUMN key_id TEXT;

-- ===========================================================================
-- 006_tenant_api_keys.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — production tenant API key store.
--
-- API keys are how machine-to-machine clients (CI bots, integrations,
-- third-party SaaS) authenticate to the control plane. Each row is a
-- single API key minted for a tenant:
--
--   * `hash` is the SHA-256 of the secret. The plaintext is shown to
--     the operator exactly once at creation time and never stored.
--     Lookups are by hash equality, so the column is a deterministic
--     digest, NOT a slow KDF — we trade KDF-style brute-force
--     resistance for O(1) lookup, justified because the underlying
--     secret is 256 random bits (32 base64url chars after the `sng_`
--     prefix). A 256-bit search space is comfortably outside the
--     reach of any offline cracker even with SHA-256.
--   * `subject` is a human-readable identity (e.g. "ci-bot",
--     "datadog-integration") audit logs use for the actor field. It
--     is NOT used for permission checks.
--   * `status` flips to 'revoked' on Revoke and never flips back —
--     a revoked key cannot be reactivated (operators mint a new
--     key instead). This matches the webhook endpoint convention.
--   * `expires_at` is optional. When set, the middleware compares
--     against `now()` and rejects expired keys without a status
--     change so a future automated job can sweep expired rows
--     into 'revoked' without racing the auth path.
--
-- The middleware looks up a presented key by hashing it once with
-- SHA-256 and querying `tenant_api_keys` by `hash`. The lookup has
-- to be cross-tenant (the request hasn't identified the tenant
-- yet — the API key IS the identification), so we expose a
-- `sng.system_role='true'` bypass on the RLS policy. The application
-- is the only thing that can set this GUC (it's a GUC, not a DB
-- role grant), and the middleware is the only call site that uses
-- the bypass.

CREATE TABLE tenant_api_keys (
    id             UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id      UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    name           TEXT NOT NULL,
    subject        TEXT NOT NULL,
    hash           BYTEA NOT NULL,
    status         TEXT NOT NULL CHECK (status IN ('active', 'revoked')),
    expires_at     TIMESTAMPTZ,
    last_used_at   TIMESTAMPTZ,
    created_by     UUID,
    created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    revoked_at     TIMESTAMPTZ
);

-- Global uniqueness on `hash`. Two tenants minting the same SHA-256
-- digest is functionally a SHA-256 collision — impossibly rare in
-- practice, but the unique constraint makes the impossibility a
-- schema invariant: a hash maps to at most one (tenant, key) pair,
-- so the cross-tenant lookup path in the middleware cannot return
-- two ambiguous rows.
CREATE UNIQUE INDEX tenant_api_keys_hash_idx ON tenant_api_keys (hash);

-- Per-tenant list ordering. Created-desc covers the only list query
-- the handler exposes (`GET /tenants/{tid}/api-keys`). Including
-- `status` in the index lets the planner skip the heap probe for
-- the common active-keys-only list filter.
CREATE INDEX tenant_api_keys_tenant_created_idx
    ON tenant_api_keys (tenant_id, status, created_at DESC, id);

ALTER TABLE tenant_api_keys ENABLE ROW LEVEL SECURITY;
ALTER TABLE tenant_api_keys FORCE ROW LEVEL SECURITY;

-- Per-tenant CRUD goes through `sng.tenant_id`. The auth middleware
-- bypass uses `sng.system_role='true'` for the cross-tenant hash
-- lookup; same pattern as webhook_deliveries.
CREATE POLICY tenant_api_keys_tenant_isolation ON tenant_api_keys
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    )
    WITH CHECK (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    );

-- ===========================================================================
-- 007_policy_bundle_sha256.up.sql
-- ===========================================================================
-- 007_policy_bundle_sha256
--
-- Add a precomputed SHA-256 digest column to policy_bundles so the
-- agent-pull endpoint can serve HEAD / If-None-Match responses
-- without round-tripping the (potentially large) bundle BYTEA into
-- application memory just to recompute the ETag.
--
-- For polling agents the common case is "I already have the current
-- bundle, give me a 304". Before this column, that path still
-- loaded the full bundle bytes from Postgres because the ETag was
-- sha256(bundle) computed in Go. With the column in place the HEAD
-- and 304 paths only need the digest + signature + key_id +
-- created_at, all of which fit on the row itself.
--
-- Backfill uses pgcrypto's digest() so the stored digest is byte-
-- identical to the value Go's crypto/sha256.Sum256 would compute,
-- meaning existing in-flight client caches keyed on the prior ETag
-- continue to match after the migration. After backfill the column
-- is set NOT NULL so the application layer can rely on it.

BEGIN;

ALTER TABLE policy_bundles
    ADD COLUMN sha256 BYTEA;

UPDATE policy_bundles
SET sha256 = digest(bundle, 'sha256');

ALTER TABLE policy_bundles
    ALTER COLUMN sha256 SET NOT NULL,
    ADD CONSTRAINT policy_bundles_sha256_length_chk
        CHECK (octet_length(sha256) = 32);

COMMIT;

-- ===========================================================================
-- 008_app_registry.up.sql
-- ===========================================================================
-- 008_app_registry — Traffic Classification & Steering Framework.
--
-- The traffic classification engine maps every flow into one of six
-- `traffic_class` values (see docs/TRAFFIC_CLASSIFICATION.md). The
-- mapping is sourced from two tables:
--
--   * app_registry            — global curated database of well-known
--                               apps (Microsoft 365, Google Workspace,
--                               …). NOT tenant-scoped; one row per
--                               app, identical content for every
--                               tenant.
--   * app_registry_overrides  — per-tenant promotions / demotions.
--                               RLS-isolated by `sng.tenant_id`.
--
-- The two-table layout mirrors the sn360 "global catalog + tenant
-- override" pattern: the global table is curated by operators and
-- refreshed by the vendor-endpoint sync job; the override table is
-- where each tenant expresses local intent.

-- ---------------------------------------------------------------------
-- app_registry
--
-- Curated global database. NOT tenant-scoped (no RLS). Application
-- code asserts admin-role on writes; reads are unrestricted because
-- the data is the same for every tenant.
-- ---------------------------------------------------------------------
CREATE TABLE app_registry (
    id              UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    name            TEXT NOT NULL,
    vendor          TEXT,
    traffic_class   TEXT NOT NULL CHECK (traffic_class IN (
        'trusted_direct',
        'trusted_media_bypass',
        'inspect_lite',
        'inspect_full',
        'tunnel_private',
        'block'
    )),
    scope           TEXT NOT NULL CHECK (scope IN ('global', 'regional')),
    -- regions is NULL for global apps; non-empty array of ISO/region
    -- codes for regional ones (e.g. {"APAC","JP"}).
    regions         TEXT[],
    -- domain patterns — wildcards allowed (e.g. "*.office.com").
    -- Stored as TEXT[] (not LTREE / regex) so the edge / agent can
    -- match them with a simple suffix walk.
    domains         TEXT[] NOT NULL,
    -- expected IP ranges for the domain-to-IP binding safety check.
    ip_ranges       CIDR[],
    -- expected certificate chain hashes (SHA256 hex) for the cert
    -- pin check.
    cert_pins       TEXT[],
    -- vendor-published URL the sync job pulls to refresh
    -- domains / ip_ranges (e.g. Microsoft's M365 endpoints JSON).
    metadata_url    TEXT,
    category        TEXT,
    -- is_system distinguishes baseline curated rows from
    -- operator-added ones. The sync job will not touch is_system=false.
    is_system       BOOLEAN NOT NULL DEFAULT TRUE,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    -- name is unique for the global catalog so operators can
    -- reference apps by a stable handle.
    UNIQUE (name),
    CHECK (cardinality(domains) > 0),
    CHECK (
        scope = 'global'
        OR (scope = 'regional' AND regions IS NOT NULL AND cardinality(regions) > 0)
    )
);

CREATE INDEX app_registry_traffic_class_idx ON app_registry (traffic_class);
CREATE INDEX app_registry_scope_idx         ON app_registry (scope);
CREATE INDEX app_registry_category_idx      ON app_registry (category);
-- GIN index on domains enables efficient `?` (array contains) lookups
-- for the "which app does this domain belong to" path; falls back to
-- in-process suffix matching for wildcards.
CREATE INDEX app_registry_domains_idx       ON app_registry USING GIN (domains);

CREATE TRIGGER app_registry_set_updated_at
    BEFORE UPDATE ON app_registry
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

-- ---------------------------------------------------------------------
-- app_registry_overrides
--
-- Per-tenant promotions / demotions of app classifications. Two
-- shapes are supported:
--
--   1. app_id IS NOT NULL  — override the classification of a
--                            global registry entry.
--   2. app_id IS NULL      — define a tenant-local app via
--                            `custom_domains` for entries that
--                            don't exist in the global catalog.
--
-- RLS-isolated via `sng.tenant_id` — same pattern as every other
-- tenant-scoped table (see docs/deploy.md).
-- ---------------------------------------------------------------------
CREATE TABLE app_registry_overrides (
    id                       UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id                UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    app_id                   UUID REFERENCES app_registry(id) ON DELETE CASCADE,
    -- custom_domains is populated only when app_id IS NULL (tenant
    -- defines a brand-new app). When app_id is set, this column is
    -- NULL and the global registry's domains list is used.
    custom_domains           TEXT[],
    traffic_class_override   TEXT NOT NULL CHECK (traffic_class_override IN (
        'trusted_direct',
        'trusted_media_bypass',
        'inspect_lite',
        'inspect_full',
        'tunnel_private',
        'block'
    )),
    -- expires_at supports auto-expiring demotions emitted by the
    -- demotion engine on transient signals (cert-pin mismatch, IP
    -- range mismatch, …). NULL = permanent override.
    expires_at               TIMESTAMPTZ,
    reason                   TEXT,
    created_at               TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at               TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    -- Either reference a global app, or define a custom one — never
    -- both, never neither.
    CHECK (
        (app_id IS NOT NULL AND custom_domains IS NULL)
        OR (app_id IS NULL AND custom_domains IS NOT NULL AND cardinality(custom_domains) > 0)
    )
);

CREATE INDEX app_registry_overrides_tenant_idx ON app_registry_overrides (tenant_id);
CREATE INDEX app_registry_overrides_app_idx    ON app_registry_overrides (app_id);
CREATE INDEX app_registry_overrides_expires_idx ON app_registry_overrides (expires_at)
    WHERE expires_at IS NOT NULL;
CREATE INDEX app_registry_overrides_custom_domains_idx
    ON app_registry_overrides USING GIN (custom_domains)
    WHERE custom_domains IS NOT NULL;

-- A tenant can only have one active override per (app_id) OR per
-- (canonical custom_domains) pair. We rely on application-level
-- enforcement for the custom_domains case because Postgres lacks
-- a stable unique-on-array-content operator. For app_id-based
-- overrides we add a partial unique index.
CREATE UNIQUE INDEX app_registry_overrides_tenant_app_uniq
    ON app_registry_overrides (tenant_id, app_id)
    WHERE app_id IS NOT NULL;

CREATE TRIGGER app_registry_overrides_set_updated_at
    BEFORE UPDATE ON app_registry_overrides
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE app_registry_overrides ENABLE ROW LEVEL SECURITY;
ALTER TABLE app_registry_overrides FORCE ROW LEVEL SECURITY;
CREATE POLICY app_registry_overrides_tenant_isolation ON app_registry_overrides
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

-- ===========================================================================
