     ARRAY['ANZ', 'AU'],
     ARRAY['*.westpac.com.au', 'westpac.com.au'],
     'finance'),
    ('ANZ Bank', 'ANZ Banking Group', 'inspect_lite', 'regional',
     ARRAY['ANZ', 'AU', 'NZ'],
     ARRAY['*.anz.com', 'anz.com', '*.anz.co.nz'],
     'finance')
ON CONFLICT (name) DO NOTHING;

-- ===========================================================================
-- 010_policy_rollouts.up.sql
-- ===========================================================================
-- 010_policy_rollouts — Progressive policy rollout state machine.
--
-- Tracks each proposed PolicyGraph as it advances through dry-run
-- (shadow / log-only on agents), canary (configurable percent of
-- the fleet enforces the new bundle, the rest stay on the
-- previous one), and full-fleet enforcement. Terminates in either
-- `completed` (operator promoted the proposed graph to canonical)
-- or `rolled_back` (operator pulled the rollout at any stage).
--
-- The state machine is enforced by a CHECK on the stage column
-- and a BEFORE UPDATE trigger that rejects illegal transitions —
-- this puts the invariant in the database so a buggy service
-- caller cannot leave the table in an impossible state
-- (e.g. completed -> canary).
--
-- RLS pattern mirrors policy_graphs / policy_signing_keys: a
-- single `tenant_isolation` USING clause that filters every read
-- and write on `sng.tenant_id` GUC equality. The migration
-- forces RLS so even superusers go through the policy when
-- connecting via the service role.

CREATE TABLE IF NOT EXISTS policy_rollouts (
    id                 UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id          UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    graph_id           UUID NOT NULL REFERENCES policy_graphs(id) ON DELETE RESTRICT,
    -- Nullable: the very first rollout on a tenant has no
    -- predecessor. ON DELETE SET NULL preserves the rollout audit
    -- trail even if an operator hard-deletes the previous graph.
    previous_graph_id  UUID REFERENCES policy_graphs(id) ON DELETE SET NULL,
    stage              TEXT NOT NULL DEFAULT 'dry_run',
    -- 0..100. Meaningful only when stage = 'canary'; we keep the
    -- value on the row across stage transitions so the audit
    -- record retains "we ran at N% before promoting / rolling
    -- back".
    canary_percent     INTEGER NOT NULL DEFAULT 0 CHECK (canary_percent >= 0 AND canary_percent <= 100),
    -- Free-form simulation_id from the simulator. Not FK'd —
    -- simulation runs are not persisted in this PR; the operator
    -- pastes the ID for audit if they want a paper trail.
    simulation_id      UUID,
    -- Optional; null when a rollback is triggered by automation
    -- (e.g. a fleet-wide error-rate alarm) rather than an
    -- operator action.
    created_by         UUID REFERENCES users(id) ON DELETE SET NULL,
    created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    notes              TEXT,

    CONSTRAINT policy_rollouts_stage_check
        CHECK (stage IN ('dry_run', 'canary', 'full', 'completed', 'rolled_back'))
);

-- Hot-path index for GetActive: each tenant typically has at
-- most one in-flight rollout. We omit the partial-unique
-- constraint deliberately (the service layer is responsible for
-- the overlap policy — see internal/service/policy/canary.go).
CREATE INDEX IF NOT EXISTS policy_rollouts_active_idx
    ON policy_rollouts (tenant_id, created_at DESC)
    WHERE stage NOT IN ('completed', 'rolled_back');

-- Listing index for the operator-facing UI.
CREATE INDEX IF NOT EXISTS policy_rollouts_list_idx
    ON policy_rollouts (tenant_id, created_at DESC, id DESC);

-- Lookup-by-graph for the "what rollouts targeted this graph"
-- view.
CREATE INDEX IF NOT EXISTS policy_rollouts_graph_idx
    ON policy_rollouts (tenant_id, graph_id);

-- ---------------------------------------------------------------------
-- Monotone-forward stage-transition trigger.
--
-- The state machine: a row may transition
--   dry_run -> canary | full | rolled_back
--   canary  -> full | rolled_back
--   full    -> completed | rolled_back
-- Terminal states (completed, rolled_back) admit no further
-- transitions. Same-stage updates are allowed so the service can
-- patch canary_percent or notes without forcing a transition.
-- ---------------------------------------------------------------------

CREATE OR REPLACE FUNCTION policy_rollouts_check_transition()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.stage = OLD.stage THEN
        RETURN NEW;
    END IF;

    IF OLD.stage IN ('completed', 'rolled_back') THEN
        RAISE EXCEPTION 'policy_rollouts: rollout % already in terminal stage %', OLD.id, OLD.stage
            USING ERRCODE = '23514';
    END IF;

    IF NEW.stage = 'rolled_back' THEN
        RETURN NEW;
    END IF;

    IF OLD.stage = 'dry_run' AND NEW.stage IN ('canary', 'full') THEN
        RETURN NEW;
    END IF;
    IF OLD.stage = 'canary' AND NEW.stage = 'full' THEN
        RETURN NEW;
    END IF;
    IF OLD.stage = 'full' AND NEW.stage = 'completed' THEN
        RETURN NEW;
    END IF;

    RAISE EXCEPTION 'policy_rollouts: illegal transition % -> %', OLD.stage, NEW.stage
        USING ERRCODE = '23514';
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER policy_rollouts_stage_transition
    BEFORE UPDATE OF stage ON policy_rollouts
    FOR EACH ROW
    EXECUTE FUNCTION policy_rollouts_check_transition();

-- ---------------------------------------------------------------------
-- Row-level security — tenant isolation via `sng.tenant_id` GUC.
-- ---------------------------------------------------------------------

ALTER TABLE policy_rollouts ENABLE ROW LEVEL SECURITY;
ALTER TABLE policy_rollouts FORCE ROW LEVEL SECURITY;
CREATE POLICY policy_rollouts_tenant_isolation ON policy_rollouts
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

COMMENT ON TABLE policy_rollouts IS
    'Progressive deployment of a proposed PolicyGraph: dry_run -> canary -> full, terminating in completed or rolled_back. See internal/repository/types.go PolicyRollout and internal/service/policy/canary.go.';

-- ===========================================================================
-- 011_policy_graphs_is_draft.up.sql
-- ===========================================================================
-- 011_policy_graphs_is_draft — Mark candidate graphs as drafts.
--
-- A policy graph is "current" when it is the highest-version row
-- that has been promoted (is_draft = false). Drafts are graphs
-- the operator has proposed but not yet promoted to live —
-- typically as part of an active rollout (see migration
-- 010_policy_rollouts). The dry-run / canary stages need to
-- store the proposed graph (so it can be FK'd from the
-- policy_rollouts row), but those stages must NOT change the
-- live policy. Without this flag, GetCurrentGraph would return
-- the proposed graph and the next call to /policy/compile would
-- promote it — defeating the dry-run isolation that the rollout
-- state machine is meant to provide.
--
-- Promotion (draft -> live) flips is_draft = false at
-- rollout-completion time. Rollback leaves is_draft = true so
-- the row remains queryable for audit but does not affect
-- GetCurrentGraph.
--
-- Backfill: existing rows pre-date the rollout API, so they are
-- all considered live (is_draft = false). The DEFAULT covers
-- the legacy path where CreateGraph callers don't supply the
-- column.
ALTER TABLE policy_graphs
    ADD COLUMN IF NOT EXISTS is_draft BOOLEAN NOT NULL DEFAULT false;

-- GetCurrentGraph is the hot path; an explicit partial index on
-- live rows makes the ORDER BY version DESC LIMIT 1 satisfy from
-- the index without scanning drafts.
CREATE INDEX IF NOT EXISTS policy_graphs_tenant_version_live_idx
    ON policy_graphs (tenant_id, version DESC)
    WHERE is_draft = false;

-- ===========================================================================
-- 012_baseline_models.up.sql
-- ===========================================================================
-- 012_baseline_models — Per-tenant statistical baselines for
-- anomaly detection.
--
-- For each (tenant_id, dimension, window_seconds) we maintain
-- an online estimator of the centre + spread of the observed
-- distribution. Two estimators are stored in parallel:
--
--   1) Welford's running mean + M2 (sum of squared deviations
--      from the running mean). This gives a numerically stable
--      sample mean + variance over the full observed history
--      WITHOUT keeping every sample, which is critical for the
--      hot path that observes one bucket per minute per
--      dimension per tenant. The standard deviation is
--      sqrt(m2 / max(samples - 1, 1)); samples < 2 is the
--      cold-start regime where we cannot yet score deviation.
--
--   2) EWMA (exponentially-weighted moving average) + EWMVAR
--      (the EW variance, EW square of deviation from EWMA).
--      Captures recent shifts faster than the Welford estimator
--      — a sustained 2-3x increase in DNS query volume after a
--      malware outbreak should trip in single-digit minutes, not
--      after weeks of contamination dilutes the Welford mean.
--      Alpha is the per-(tenant, dimension) decay factor in
--      (0, 1]; alpha = 1 collapses EWMA to "last observation"
--      and alpha = 0 freezes the estimator.
--
-- The anomaly detector (internal/service/baseline/anomaly.go)
-- evaluates BOTH estimators and uses max(|z_welford|,
-- |z_ewma|) as the deviation score. This catches both "slow
-- drift" anomalies (Welford trips because the long-running mean
-- has not yet absorbed the new regime) AND "sudden spike"
-- anomalies (EWMA trips because alpha=0.1 brings the recent
-- regime into the mean quickly).
--
-- z_threshold is the per-(tenant, dimension) operator-tunable
-- z-score above which an alert is emitted. Default 3.0 captures
-- ~0.27% of normal observations under a Gaussian assumption,
-- which empirically is the right knee for "novel enough to wake
-- an operator". Per-tenant tuning lives in the alert.Feedback
-- loop (migration 013).
--
-- version is an optimistic-lock counter incremented on every
-- update. The Engine's update path is read-modify-write
-- (load baseline, fold new sample, write back) so concurrent
-- observers from a fan-out goroutine MUST NOT silently overwrite
-- each other — the postgres UPDATE includes `WHERE version =
-- $old_version` and a mismatch surfaces as ErrConflict to the
-- service layer, which retries.
--
-- RLS mirrors the policy_rollouts pattern: a single tenant
-- isolation policy keyed off sng.tenant_id, FORCE'd so the
-- service role goes through the policy.

CREATE TABLE IF NOT EXISTS baseline_models (
    id                   UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id            UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    -- A dotted-path label for the metric being modelled, e.g.
    -- "flow.bytes_total.unclassified", "dns.queries.NXDOMAIN",
    -- "auth.failures.password", "policy.deny_rate".
    -- Free-form on purpose: the catalog of built-in dimensions
    -- lives in internal/service/baseline/dimensions.go so it
    -- can evolve without a schema migration.
    dimension            TEXT NOT NULL,
    -- Bucket size in seconds. 60 (one-minute buckets) is the
    -- default; longer windows (3600 = hourly) for noisy metrics
    -- like total bytes_in across a multi-thousand-device tenant.
    window_seconds       INTEGER NOT NULL CHECK (window_seconds > 0),

    -- Welford state.
    samples              BIGINT  NOT NULL DEFAULT 0,
    mean                 DOUBLE PRECISION NOT NULL DEFAULT 0.0,
    m2                   DOUBLE PRECISION NOT NULL DEFAULT 0.0,

    -- EWMA state. Cold-start (samples = 0) uses the first
    -- observation directly as the initial ewma; ewma_var grows
    -- from zero as deviations accumulate.
    ewma                 DOUBLE PRECISION NOT NULL DEFAULT 0.0,
    ewma_var             DOUBLE PRECISION NOT NULL DEFAULT 0.0,
    alpha                DOUBLE PRECISION NOT NULL DEFAULT 0.1
        CHECK (alpha > 0.0 AND alpha <= 1.0),

    -- Operator-tunable alerting threshold; the feedback loop in
    -- alert.Feedback adjusts this per-tenant in response to
    -- accumulated false-positive markers.
    z_threshold          DOUBLE PRECISION NOT NULL DEFAULT 3.0
        CHECK (z_threshold > 0.0),

    last_observed_at     TIMESTAMPTZ,
    last_updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    -- Optimistic lock for read-modify-write updates.
    version              BIGINT NOT NULL DEFAULT 0,

    -- One model per (tenant, dimension, window). A request for
    -- a (tenant, dim) at a window we have no model for yields a
    -- cold-start insert; subsequent observations into the same
    -- tuple round-trip through this row.
    UNIQUE (tenant_id, dimension, window_seconds)
);

-- Hot path is GetForDimension; (tenant, dim, window) UNIQUE
-- index already satisfies that lookup. The list-for-tenant
-- (operator-facing) view orders by last_updated_at to surface
-- the most recently active models.
CREATE INDEX IF NOT EXISTS baseline_models_recent_idx
    ON baseline_models (tenant_id, last_updated_at DESC);

-- RLS.
ALTER TABLE baseline_models ENABLE ROW LEVEL SECURITY;
ALTER TABLE baseline_models FORCE ROW LEVEL SECURITY;
CREATE POLICY baseline_models_tenant_isolation ON baseline_models
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

COMMENT ON TABLE baseline_models IS
    'Per-tenant statistical baselines (Welford + EWMA) backing the anomaly detector. See internal/service/baseline/.';

-- ===========================================================================
-- 013_alerts.up.sql
-- ===========================================================================
-- 013_alerts — Operator-facing alert store + suppression
-- rules + per-alert feedback.
--
-- The lifecycle of an alert:
--
--   open (default at emit time) --> acknowledged --> resolved
--                              \--> suppressed (silently muted
--                                   by a matching rule; never
--                                   notified)
--
-- "suppressed" is a terminal-ish state in the sense that no
-- notification is emitted, but the row is still persisted so an
-- operator reviewing the suppression rule can see what it
-- silenced (audit trail). Suppression matching happens at emit
-- time (alert.Router.Emit) — if a matching rule exists, the
-- alert is stored with state = 'suppressed' and the matching
-- rule id is recorded on `suppressed_by` for the audit trail.
--
-- Severity scale is the classic three-bucket info|warning|
-- critical mapping so SIEM exports (PR D) can map cleanly to
-- target systems without an N:M lookup table.
--
-- evidence is JSONB rather than columnar because the shape is
-- per-(kind, dimension) — flow.bytes_per_app_class produces
-- a different evidence payload than auth.failures, and we don't
-- want to bloat the schema with optional columns per dimension.
-- For SIEM-export consumers, the alert.Router stringifies the
-- evidence at emit time.
--
-- Table ordering: alert_suppressions is created first because
-- alerts.suppressed_by has an FK to it. PostgreSQL requires the
-- referenced table to exist before the FK is declared inside a
-- CREATE TABLE statement.

CREATE TABLE IF NOT EXISTS alert_suppressions (
    id                   UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id            UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,

    -- kind / dimension matchers. NULL = match any. Concrete
    -- string = exact match. We deliberately do not support glob
    -- patterns at the DB layer to keep the suppression-match
    -- query a simple equality test on indexable columns.
    kind                 TEXT,
    dimension            TEXT,

    -- Required: an operator MUST justify a suppression so the
    -- audit log captures "why does this alert never fire".
    reason               TEXT NOT NULL,

    -- created_by is nullable for two reasons:
    --   1) ON DELETE SET NULL on the FK — if we keep NOT NULL
    --      here, deleting any operator who has ever authored a
    --      suppression rule would fail with a constraint
    --      violation, which makes user-offboarding workflows
    --      brittle (the matching pattern is intentionally
    --      retained for audit; the link to the now-deleted
    --      user is what gets nulled).
    --   2) API-key-only operators have no user mapping (the
    --      auth middleware passes a nil actor), so requiring
    --      a non-null FK would 500 those callers. The audit
    --      surface logs the request principal separately
    --      regardless of whether a user_id is available.
    created_by           UUID REFERENCES users(id) ON DELETE SET NULL,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    -- NULL = never expires; the Router treats expires_at < now()
    -- as "not active" so a forgotten suppression doesn't outlive
    -- the operator who set it.
    expires_at           TIMESTAMPTZ,

    CONSTRAINT alert_suppressions_scope_nonempty
        CHECK (kind IS NOT NULL OR dimension IS NOT NULL)
);

CREATE TABLE IF NOT EXISTS alerts (
    id                   UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id            UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,

    -- Dotted-path alert kind. Convention: "<source>.<event>",
    -- e.g. "baseline.anomaly", "policy.deny_rate.spike",
    -- "auth.brute_force". The catalog of built-in kinds lives
    -- in internal/service/alert/kinds.go.
    kind                 TEXT NOT NULL,
    severity             TEXT NOT NULL DEFAULT 'warning',
    dimension            TEXT NOT NULL,

    -- Statistical context — copied off the baseline at emit time
    -- so the alert is self-explaining even if the baseline drifts
    -- after the fact.
    observed_value       DOUBLE PRECISION NOT NULL,
    baseline_mean        DOUBLE PRECISION NOT NULL,
    baseline_stddev      DOUBLE PRECISION NOT NULL,
    z_score              DOUBLE PRECISION NOT NULL,

    window_start         TIMESTAMPTZ NOT NULL,
    window_end           TIMESTAMPTZ NOT NULL,
    -- The bucket size in seconds of the underlying baseline
    -- model. Snapshot-copied here (rather than derived from
    -- window_end - window_start) so the feedback tuning loop
    -- can filter feedback rows by (dimension, window_seconds)
    -- without ambiguity: a 60s bucket and a 3600s bucket on the
    -- same dimension are independently-tuned series, and merging
    -- their FP rates would silently push the wrong threshold up.
    -- See PR #40 round-9 ANALYSIS_0002.
    window_seconds       INTEGER NOT NULL CHECK (window_seconds > 0),

    -- Human-facing one-liner; the Router formats this from the
    -- emit payload so the operator portal has something to show
    -- without re-rendering the evidence blob.
    summary              TEXT NOT NULL,
    evidence             JSONB NOT NULL DEFAULT '{}'::jsonb,

    state                TEXT NOT NULL DEFAULT 'open',

    suppressed_by        UUID REFERENCES alert_suppressions(id) ON DELETE SET NULL,
    acknowledged_by      UUID REFERENCES users(id) ON DELETE SET NULL,
    acknowledged_at      TIMESTAMPTZ,
    resolved_by          UUID REFERENCES users(id) ON DELETE SET NULL,
    resolved_at          TIMESTAMPTZ,

    created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT alerts_severity_check
        CHECK (severity IN ('info', 'warning', 'critical')),
    CONSTRAINT alerts_state_check
        CHECK (state IN ('open', 'acknowledged', 'resolved', 'suppressed'))
);

CREATE TABLE IF NOT EXISTS alert_feedback (
    id                   UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id            UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    alert_id             UUID NOT NULL REFERENCES alerts(id) ON DELETE CASCADE,

    -- true_positive: alert was actionable (do not adjust tuning)
    -- false_positive: alert was not actionable (tighten tuning)
    -- noise: alert was technically correct but operationally
    --        useless (e.g. periodic legitimate spike). Adjust
    --        tuning but less aggressively than false_positive.
    decision             TEXT NOT NULL,
    notes                TEXT,

    -- Nullable for the same reason as alert_suppressions.created_by:
    -- ON DELETE SET NULL + API-key callers without user mapping.
    -- The decision + alert_id are what the tuning loop needs, the
    -- author is metadata for the operator timeline.
    created_by           UUID REFERENCES users(id) ON DELETE SET NULL,
    created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT alert_feedback_decision_check
        CHECK (decision IN ('true_positive', 'false_positive', 'noise')),
    -- One feedback per alert. If an operator wants to revise
    -- they DELETE + re-INSERT through the API rather than
    -- silently overwriting history.
    UNIQUE (alert_id)
);

-- ---- Indexes -------------------------------------------------

-- Listing index — operator portal lists "open alerts for this
-- tenant, newest first".
CREATE INDEX IF NOT EXISTS alerts_list_idx
    ON alerts (tenant_id, created_at DESC, id DESC);

-- State + recency index — the "open queue" hot path filters by
-- state = 'open' AND tenant_id, ordered by created_at DESC.
CREATE INDEX IF NOT EXISTS alerts_open_idx
    ON alerts (tenant_id, created_at DESC)
    WHERE state = 'open';

-- Dimension lookup — used by alert.Feedback to compute the
-- per-dimension false-positive rate when re-tuning a baseline.
CREATE INDEX IF NOT EXISTS alerts_dimension_idx
    ON alerts (tenant_id, dimension);

-- Suppression match index — the Router checks "is this (kind,
-- dimension) currently suppressed" on every emit. (tenant_id,
-- kind) covers the most common "wildcard dimension" case;
-- (tenant_id, dimension) covers the "wildcard kind" case.
CREATE INDEX IF NOT EXISTS alert_suppressions_kind_idx
    ON alert_suppressions (tenant_id, kind);
CREATE INDEX IF NOT EXISTS alert_suppressions_dimension_idx
    ON alert_suppressions (tenant_id, dimension);

-- Feedback aggregation — alert.Feedback scans feedback by tenant
-- + dimension to compute the FP rate per dimension.
CREATE INDEX IF NOT EXISTS alert_feedback_dimension_idx
    ON alert_feedback (tenant_id, alert_id, created_at DESC);

-- ---- RLS -----------------------------------------------------

ALTER TABLE alerts              ENABLE ROW LEVEL SECURITY;
ALTER TABLE alerts              FORCE ROW LEVEL SECURITY;
ALTER TABLE alert_suppressions  ENABLE ROW LEVEL SECURITY;
ALTER TABLE alert_suppressions  FORCE ROW LEVEL SECURITY;
ALTER TABLE alert_feedback      ENABLE ROW LEVEL SECURITY;
ALTER TABLE alert_feedback      FORCE ROW LEVEL SECURITY;

CREATE POLICY alerts_tenant_isolation ON alerts
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);
CREATE POLICY alert_suppressions_tenant_isolation ON alert_suppressions
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);
CREATE POLICY alert_feedback_tenant_isolation ON alert_feedback
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

COMMENT ON TABLE alerts IS
    'Operator-facing alerts produced by the baseline.Detector and other sources, with self-explaining statistical context.';
COMMENT ON TABLE alert_suppressions IS
    'Per-tenant suppression rules — match by kind and/or dimension, with required reason for audit.';
COMMENT ON TABLE alert_feedback IS
    'Operator feedback on alert quality, feeding the alert.Feedback tuning loop.';

-- ===========================================================================
-- 014_integrations.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — integration connectors migration.
--
-- Adds two tables:
--   - integration_connectors : per-tenant external destinations (syslog,
--                              siem_webhook, jira, servicenow). Config + Secret
--                              are typed JSONB blobs owned by the connector
--                              plugin; the migration only pins the lifecycle
--                              fields (status, type, last-test-state).
--   - integration_deliveries : append-only delivery attempts per
--                              (connector, event) pair. Worker drains via
--                              FOR UPDATE SKIP LOCKED on the pending index.
--
-- Both tables are RLS-scoped to `sng.tenant_id`. The shape mirrors
-- webhook_endpoints / webhook_deliveries deliberately: a future
-- maintainer comparing the two pipes recognises the lifecycle
-- and the operational tooling is the same.
--
-- Secret encryption-at-rest is delegated to disk encryption / TDE in
-- the same way as webhook_endpoints.signing_secret. Per-row envelope
-- encryption is a known follow-up for the FedRAMP-track deployment.

CREATE TABLE IF NOT EXISTS integration_connectors (
    id                UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id         UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    type              TEXT        NOT NULL
                      CHECK (type IN ('syslog', 'siem_webhook', 'jira', 'servicenow')),
    name              TEXT        NOT NULL,
    description       TEXT        NOT NULL DEFAULT '',
    event_types       TEXT[]      NOT NULL DEFAULT ARRAY[]::TEXT[],
    config            JSONB       NOT NULL DEFAULT '{}'::jsonb,
    secret            BYTEA       NOT NULL DEFAULT '\x'::bytea,
    status            TEXT        NOT NULL DEFAULT 'active'
                      CHECK (status IN ('active', 'disabled')),
    last_test_result  TEXT        NOT NULL DEFAULT 'never'
                      CHECK (last_test_result IN ('never', 'success', 'failure')),
    last_test_at      TIMESTAMPTZ,
    last_test_error   TEXT        NOT NULL DEFAULT '',
    created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (tenant_id, name)
);

CREATE INDEX IF NOT EXISTS idx_integration_connectors_tenant
    ON integration_connectors (tenant_id);
CREATE INDEX IF NOT EXISTS idx_integration_connectors_tenant_status
    ON integration_connectors (tenant_id, status);
CREATE INDEX IF NOT EXISTS idx_integration_connectors_tenant_type
    ON integration_connectors (tenant_id, type);

CREATE TRIGGER integration_connectors_set_updated_at
    BEFORE UPDATE ON integration_connectors
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE integration_connectors ENABLE ROW LEVEL SECURITY;
ALTER TABLE integration_connectors FORCE ROW LEVEL SECURITY;

CREATE POLICY integration_connectors_tenant_isolation ON integration_connectors
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid)
    WITH CHECK (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

CREATE TABLE IF NOT EXISTS integration_deliveries (
    id                 UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id          UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    connector_id       UUID        NOT NULL REFERENCES integration_connectors(id) ON DELETE CASCADE,
    event_type         TEXT        NOT NULL,
    payload            JSONB       NOT NULL,
    status             TEXT        NOT NULL DEFAULT 'pending'
                       CHECK (status IN ('pending', 'processing', 'delivered', 'failed', 'exhausted')),
    attempts           INTEGER     NOT NULL DEFAULT 0,
    last_attempt_at    TIMESTAMPTZ,
    last_error         TEXT        NOT NULL DEFAULT '',
    next_retry_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    response_status    INTEGER     NOT NULL DEFAULT 0,
    -- ExternalReference: e.g. Jira issue key "SEC-1234", ServiceNow sys_id
    -- "abc123...". Empty until the connector returns it on first
    -- successful Deliver; immutable thereafter so retry / update
    -- targets are stable.
    external_reference TEXT        NOT NULL DEFAULT '',
    created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_integration_deliveries_tenant
    ON integration_deliveries (tenant_id);
CREATE INDEX IF NOT EXISTS idx_integration_deliveries_pending_next
    ON integration_deliveries (status, next_retry_at)
    WHERE status IN ('pending', 'processing');
CREATE INDEX IF NOT EXISTS idx_integration_deliveries_connector
    ON integration_deliveries (connector_id);

ALTER TABLE integration_deliveries ENABLE ROW LEVEL SECURITY;
ALTER TABLE integration_deliveries FORCE ROW LEVEL SECURITY;

CREATE POLICY integration_deliveries_tenant_isolation ON integration_deliveries
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    )
    WITH CHECK (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    );

-- ===========================================================================
-- 015_msps.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — MSP hierarchy migration.
--
-- Adds the Managed Service Provider hierarchy on top of the
-- existing tenant model. An MSP is a top-level entity that owns
-- (or co-manages) one or more tenants and supplies a shared
-- branding default + a bulk-operations surface that fans out
-- across its tenant cohort.
--
-- Tables introduced:
--   - msps          : top-level MSP catalog (NOT RLS-scoped).
--                     Mirrors the `tenants` table's role as a
--                     platform-level entity that application code
--                     scopes via policy rather than RLS GUC.
--   - msp_tenants   : many-to-many MSP <-> tenant binding. Many-to-many
--                     supports the co-management handoff scenario where
--                     a tenant is briefly bound to two MSPs (outgoing
--                     + incoming) during the transition. Day-to-day,
--                     a tenant has exactly one `owner` binding and
--                     zero or more `co_manager` bindings.
--
-- Tenants pick up a denormalised `msp_id UUID NULL` column pointing
-- at the **primary** owner-binding MSP. This denormalisation is
-- deliberate: RLS policies that filter `tenants` by msp_id need a
-- single-column predicate that the planner can index — the join
-- via `msp_tenants` would force a sub-select on every read on the
-- hot path. The application keeps `tenants.msp_id` and the
-- `relationship='owner'` row in `msp_tenants` in sync via the MSP
-- service's AssignTenant path.
--
-- Existing `roles.scope` already lists 'msp' as a valid value
-- (migration 001), so no DDL change is needed on the roles table.
--
-- RLS extension: a new GUC `sng.msp_id` complements the existing
-- `sng.tenant_id`. When `sng.msp_id` is set on a connection, the
-- `tenants` table grants read access to every tenant where
-- `tenant.msp_id = current_setting('sng.msp_id')::uuid`. This
-- lets an MSP-scoped session iterate across its tenant cohort
-- without setting `sng.tenant_id` for each one (which would
-- otherwise be an N-round-trip pattern for bulk operations).
--
-- The `tenants` RLS policy intentionally remains permissive when
-- neither GUC is set (matches the pre-existing fail-closed pattern
-- in migration 001: `current_setting(..., true)` returns NULL
-- instead of erroring, and the NULL comparison yields zero rows).

CREATE TABLE IF NOT EXISTS msps (
    id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    name        TEXT NOT NULL,
    -- Slug uniqueness is enforced by a partial unique index (see
    -- msps_slug_uniq_idx below) instead of an inline UNIQUE
    -- constraint, so soft-deleted MSPs do not block slug reuse.
    -- This matches the memory backend's "uniqueness ignores
    -- deleted_at IS NOT NULL" check and the analogous
    -- tenants(msp_id) partial unique index further down.
    slug        TEXT NOT NULL,
    status      TEXT NOT NULL DEFAULT 'active'
                CHECK (status IN ('active', 'suspended', 'deleted')),
    branding    JSONB NOT NULL DEFAULT '{}'::jsonb,
    settings    JSONB NOT NULL DEFAULT '{}'::jsonb,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    deleted_at  TIMESTAMPTZ
);

CREATE UNIQUE INDEX IF NOT EXISTS msps_slug_uniq_idx
    ON msps (slug) WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS msps_status_idx
    ON msps (status) WHERE deleted_at IS NULL;

CREATE TRIGGER msps_set_updated_at
    BEFORE UPDATE ON msps
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

-- msps is intentionally NOT RLS-protected. Mirrors `tenants` — the
-- top-level entity table is gated by application authorization
-- (platform_admin sees all; msp_admin sees own row only). RLS on
-- the table itself would prevent the platform_admin path.

-- ---------------------------------------------------------------------
-- msp_tenants
--
-- Many-to-many binding. `relationship` distinguishes the primary
-- owner from co-managers (read-only collaborators).
--
-- Composite PK on (msp_id, tenant_id): one binding per (msp, tenant)
-- pair, even if relationship is updated in place.
-- ---------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS msp_tenants (
    msp_id        UUID NOT NULL REFERENCES msps(id) ON DELETE CASCADE,
    tenant_id     UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    relationship  TEXT NOT NULL DEFAULT 'owner'
                  CHECK (relationship IN ('owner', 'co_manager')),
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_by    UUID REFERENCES users(id) ON DELETE SET NULL,
    PRIMARY KEY (msp_id, tenant_id)
);

CREATE INDEX IF NOT EXISTS msp_tenants_msp_idx
    ON msp_tenants (msp_id);
CREATE INDEX IF NOT EXISTS msp_tenants_tenant_idx
    ON msp_tenants (tenant_id);

-- A tenant can have at most ONE `owner` binding at any time. The
-- partial unique index enforces this at the storage layer so the
-- denormalised `tenants.msp_id` stays consistent under concurrent
-- AssignTenant calls.
CREATE UNIQUE INDEX IF NOT EXISTS msp_tenants_one_owner_per_tenant_idx
    ON msp_tenants (tenant_id)
    WHERE relationship = 'owner';

-- ---------------------------------------------------------------------
-- tenants.msp_id (denormalised primary owner)
-- ---------------------------------------------------------------------
ALTER TABLE tenants
    ADD COLUMN IF NOT EXISTS msp_id UUID
        REFERENCES msps(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS tenants_msp_idx
    ON tenants (msp_id) WHERE deleted_at IS NULL AND msp_id IS NOT NULL;

-- Augment tenants RLS so an MSP-scoped session sees every tenant
-- under its umbrella in one query instead of one SET-and-SELECT
-- per tenant.
--
-- The original tenants table in migration 001 does NOT have RLS
-- enabled (tenants is platform-scoped). The MSP cohort filter is
-- enforced at the application layer in the MSP service's
-- ListTenants path; we add an INDEX above so that path stays fast.

-- ===========================================================================
-- 016_casb.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — CASB discovery migration.
--
-- Phase 4 (PROPOSAL.md §10): API-mode CASB discovery + top SaaS
-- API connectors (M365, Google Workspace, Slack, Salesforce).
--
-- Adds three tables:
--   - casb_connectors       : per-tenant SaaS API connectors.
--   - casb_discovered_apps  : SaaS apps found by connectors.
--   - casb_posture_checks   : config posture assessment results.
--
-- All tables are RLS-scoped to `sng.tenant_id`.

CREATE TABLE IF NOT EXISTS casb_connectors (
    id            UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id     UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    type          TEXT        NOT NULL
                  CHECK (type IN ('m365', 'google', 'slack', 'salesforce')),
    name          TEXT        NOT NULL,
    status        TEXT        NOT NULL DEFAULT 'configuring'
                  CHECK (status IN ('active', 'disabled', 'error', 'configuring')),
    config        JSONB       NOT NULL DEFAULT '{}'::jsonb,
    secret        BYTEA       NOT NULL DEFAULT '\x'::bytea,
    last_sync_at  TIMESTAMPTZ,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (tenant_id, name)
);

CREATE INDEX IF NOT EXISTS idx_casb_connectors_tenant
    ON casb_connectors (tenant_id);
CREATE INDEX IF NOT EXISTS idx_casb_connectors_tenant_status
    ON casb_connectors (tenant_id, status);
CREATE INDEX IF NOT EXISTS idx_casb_connectors_tenant_type
    ON casb_connectors (tenant_id, type);

CREATE TRIGGER casb_connectors_set_updated_at
    BEFORE UPDATE ON casb_connectors
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE casb_connectors ENABLE ROW LEVEL SECURITY;
ALTER TABLE casb_connectors FORCE ROW LEVEL SECURITY;

CREATE POLICY casb_connectors_tenant_isolation ON casb_connectors
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid)
    WITH CHECK (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

CREATE TABLE IF NOT EXISTS casb_discovered_apps (
    id            UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id     UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    name          TEXT        NOT NULL,
    vendor        TEXT        NOT NULL DEFAULT '',
    category      TEXT        NOT NULL DEFAULT '',
    risk_score    INTEGER     NOT NULL DEFAULT 0,
    users_count   INTEGER     NOT NULL DEFAULT 0,
    first_seen    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    last_seen     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (tenant_id, name)
);

CREATE INDEX IF NOT EXISTS idx_casb_discovered_apps_tenant
    ON casb_discovered_apps (tenant_id);

ALTER TABLE casb_discovered_apps ENABLE ROW LEVEL SECURITY;
ALTER TABLE casb_discovered_apps FORCE ROW LEVEL SECURITY;

CREATE POLICY casb_discovered_apps_tenant_isolation ON casb_discovered_apps
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid)
    WITH CHECK (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

CREATE TABLE IF NOT EXISTS casb_posture_checks (
    id            UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id     UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    app_id        UUID        NOT NULL REFERENCES casb_discovered_apps(id) ON DELETE CASCADE,
    check_name    TEXT        NOT NULL,
    status        TEXT        NOT NULL DEFAULT 'warn'
                  CHECK (status IN ('pass', 'fail', 'warn')),
    details       TEXT        NOT NULL DEFAULT '',
    assessed_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_casb_posture_checks_tenant
    ON casb_posture_checks (tenant_id);
CREATE INDEX IF NOT EXISTS idx_casb_posture_checks_app
    ON casb_posture_checks (app_id);

ALTER TABLE casb_posture_checks ENABLE ROW LEVEL SECURITY;
ALTER TABLE casb_posture_checks FORCE ROW LEVEL SECURITY;

CREATE POLICY casb_posture_checks_tenant_isolation ON casb_posture_checks
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid)
    WITH CHECK (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

-- ===========================================================================
-- 017_dlp.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — DLP (Data Loss Prevention) migration.
--
-- Phase 4: web + SaaS DLP — regex, MIP labels, document fingerprints.
--
-- Tables introduced:
--   - dlp_policies      : tenant-scoped DLP policy definitions with
--                         JSONB-encoded rules, action, and enable flag.
--   - dlp_fingerprints  : registered document fingerprints for
--                         near-duplicate detection via SimHash.
--   - dlp_matches       : audit trail recording every time a DLP
--                         policy fires against inspected content.
--
-- All three tables are RLS-protected via the existing
-- `sng.tenant_id` GUC pattern. Indexes are designed for the hot
-- path: "list all enabled policies for a tenant" and "list all
-- fingerprints for a tenant".

-- dlp_policies ----------------------------------------------------------

CREATE TABLE IF NOT EXISTS dlp_policies (
    id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id   UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    name        TEXT NOT NULL,
    description TEXT NOT NULL DEFAULT '',
    rules       JSONB NOT NULL DEFAULT '[]'::jsonb,
    action      TEXT NOT NULL DEFAULT 'log'
                CHECK (action IN ('log', 'block', 'encrypt', 'redact')),
    enabled     BOOLEAN NOT NULL DEFAULT true,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS dlp_policies_tenant_idx
    ON dlp_policies (tenant_id);
CREATE INDEX IF NOT EXISTS dlp_policies_tenant_enabled_idx
    ON dlp_policies (tenant_id) WHERE enabled = true;

CREATE TRIGGER dlp_policies_set_updated_at
    BEFORE UPDATE ON dlp_policies
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE dlp_policies ENABLE ROW LEVEL SECURITY;

CREATE POLICY dlp_policies_tenant_isolation ON dlp_policies
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
    );

-- dlp_fingerprints ------------------------------------------------------

CREATE TABLE IF NOT EXISTS dlp_fingerprints (
    id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id     UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    name          TEXT NOT NULL,
    hash          BYTEA NOT NULL,
    content_type  TEXT NOT NULL DEFAULT '',
    registered_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS dlp_fingerprints_tenant_idx
    ON dlp_fingerprints (tenant_id);

ALTER TABLE dlp_fingerprints ENABLE ROW LEVEL SECURITY;

CREATE POLICY dlp_fingerprints_tenant_isolation ON dlp_fingerprints
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
    );

-- dlp_matches (audit trail) --------------------------------------------

CREATE TABLE IF NOT EXISTS dlp_matches (
    id         UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id  UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    policy_id  UUID NOT NULL REFERENCES dlp_policies(id) ON DELETE CASCADE,
    source     TEXT NOT NULL DEFAULT '',
    matched_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    details    JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS dlp_matches_tenant_idx
    ON dlp_matches (tenant_id);
CREATE INDEX IF NOT EXISTS dlp_matches_policy_idx
    ON dlp_matches (policy_id);
CREATE INDEX IF NOT EXISTS dlp_matches_matched_at_idx
    ON dlp_matches (tenant_id, matched_at DESC);

ALTER TABLE dlp_matches ENABLE ROW LEVEL SECURITY;

CREATE POLICY dlp_matches_tenant_isolation ON dlp_matches
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
    );

-- ===========================================================================
-- 018_browser_policies.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — browser protection policies migration.
--
-- Phase 4, Task 43: Browser Protection Service.
--
-- Adds the browser_policies table for managing browser-level
-- enforcement: download/upload restriction, clipboard control,
-- print control, screenshot prevention, and URL category blocking.
--
-- RLS: tenant-scoped via sng.tenant_id, same contract as sites.

CREATE TABLE IF NOT EXISTS browser_policies (
    id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id   UUID NOT NULL REFERENCES tenants(id),
    name        TEXT NOT NULL,
    -- Rules is a JSONB array of {type, condition, action} objects.
    rules       JSONB NOT NULL DEFAULT '[]'::jsonb,
    action      TEXT NOT NULL DEFAULT 'block'
                CHECK (action IN ('block', 'allow', 'warn', 'log')),
    scope       TEXT NOT NULL DEFAULT 'user'
                CHECK (scope IN ('user', 'group', 'site')),
    enabled     BOOLEAN NOT NULL DEFAULT true,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Per-tenant name uniqueness.
CREATE UNIQUE INDEX IF NOT EXISTS browser_policies_tenant_name_uniq
    ON browser_policies (tenant_id, name);

-- Tenant lookup index for List queries.
CREATE INDEX IF NOT EXISTS browser_policies_tenant_id_idx
    ON browser_policies (tenant_id);

-- RLS policy: same pattern as sites.
ALTER TABLE browser_policies ENABLE ROW LEVEL SECURITY;

CREATE POLICY browser_policies_tenant_isolation ON browser_policies
    USING (tenant_id = current_setting('sng.tenant_id', true)::uuid);

-- ===========================================================================
-- 019_data_classification.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — data classification taxonomy migration.
--
-- Phase 4, Task 46: Data Classification Taxonomy.
--
-- Adds the data_classifications table for hierarchical data
-- classification: Public, Internal, Confidential, Restricted,
-- Top Secret. Per-tenant customization of labels and handling
-- rules. DLP policy matches map to classification levels.

CREATE TABLE IF NOT EXISTS data_classifications (
    id              UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id       UUID NOT NULL REFERENCES tenants(id),
    label           TEXT NOT NULL,
    level           TEXT NOT NULL
                    CHECK (level IN ('public', 'internal', 'confidential', 'restricted', 'top_secret')),
    description     TEXT NOT NULL DEFAULT '',
    handling_rules  JSONB NOT NULL DEFAULT '{}'::jsonb,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Per-tenant level uniqueness (one entry per level per tenant).
CREATE UNIQUE INDEX IF NOT EXISTS data_classifications_tenant_level_uniq
    ON data_classifications (tenant_id, level);

-- Tenant lookup index.
CREATE INDEX IF NOT EXISTS data_classifications_tenant_id_idx
    ON data_classifications (tenant_id);

-- RLS policy.
ALTER TABLE data_classifications ENABLE ROW LEVEL SECURITY;

CREATE POLICY data_classifications_tenant_isolation ON data_classifications
    USING (tenant_id = current_setting('sng.tenant_id', true)::uuid);

-- ===========================================================================
-- 020_scim_external_ids.up.sql
-- ===========================================================================
-- Migration 020: SCIM external IDs
-- Adds index on users.external_id for SCIM filter fast path;
-- adds external_id to roles table for SCIM group mapping.

-- Index for SCIM filter queries: lookup by (tenant_id, external_id).
-- external_id already exists on users (see types.go); add an index
-- for the SCIM filter fast path.
CREATE INDEX IF NOT EXISTS idx_users_tenant_external_id
    ON users (tenant_id, external_id)
    WHERE external_id != '';

-- Roles: external_id for SCIM group mapping.
ALTER TABLE roles
    ADD COLUMN IF NOT EXISTS external_id TEXT NOT NULL DEFAULT '';

CREATE INDEX IF NOT EXISTS idx_roles_tenant_external_id
    ON roles (tenant_id, external_id)
    WHERE external_id != '' AND tenant_id IS NOT NULL;

-- ===========================================================================
-- 021_device_enrollment.up.sql
-- ===========================================================================
-- Migration 021: Device enrollment tables.
-- Adds device_enrollments and device_certificates tables for the
-- claim-token enrollment flow (PROPOSAL.md §7, ARCHITECTURE.md §3.4).

CREATE TYPE device_enrollment_status AS ENUM ('enrolled', 'active', 'revoked');

CREATE TABLE device_enrollments (
    device_id   UUID        NOT NULL,
    tenant_id   UUID        NOT NULL REFERENCES tenants(id),
    public_key  BYTEA       NOT NULL CHECK (octet_length(public_key) = 32),
    status      device_enrollment_status NOT NULL DEFAULT 'enrolled',
    enrolled_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    last_cert_issued_at TIMESTAMPTZ,
    revoked_at  TIMESTAMPTZ,
    PRIMARY KEY (device_id, tenant_id)
);

-- RLS policy on tenant_id.
ALTER TABLE device_enrollments ENABLE ROW LEVEL SECURITY;
CREATE POLICY device_enrollments_tenant ON device_enrollments
    USING (tenant_id::text = current_setting('sng.tenant_id', true))
    WITH CHECK (tenant_id::text = current_setting('sng.tenant_id', true));

-- Allow system-role bypass for cross-tenant operations.
CREATE POLICY device_enrollments_system ON device_enrollments
    USING (current_setting('sng.system_role', true) = 'true')
    WITH CHECK (current_setting('sng.system_role', true) = 'true');

-- Partial unique index: only one active/enrolled enrollment per
-- (tenant_id, device_id). Revoked rows are excluded so a device
-- can be re-enrolled after revocation.
CREATE UNIQUE INDEX idx_device_enrollments_active
    ON device_enrollments (tenant_id, device_id)
    WHERE status != 'revoked';

CREATE TABLE device_certificates (
    id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    device_id   UUID        NOT NULL,
    tenant_id   UUID        NOT NULL REFERENCES tenants(id),
    serial      TEXT        NOT NULL,
    cert_pem    TEXT        NOT NULL,
    issued_at   TIMESTAMPTZ NOT NULL DEFAULT now(),
    expires_at  TIMESTAMPTZ NOT NULL,
    revoked_at  TIMESTAMPTZ
);

-- RLS policy on tenant_id.
ALTER TABLE device_certificates ENABLE ROW LEVEL SECURITY;
CREATE POLICY device_certificates_tenant ON device_certificates
    USING (tenant_id::text = current_setting('sng.tenant_id', true))
    WITH CHECK (tenant_id::text = current_setting('sng.tenant_id', true));

CREATE POLICY device_certificates_system ON device_certificates
    USING (current_setting('sng.system_role', true) = 'true')
    WITH CHECK (current_setting('sng.system_role', true) = 'true');

CREATE INDEX idx_device_certificates_device
    ON device_certificates (tenant_id, device_id);

-- ===========================================================================
-- 022_compliance.up.sql
-- ===========================================================================
-- 022_compliance — Compliance reports table.
--
-- Stores generated compliance assessment reports per tenant/framework.
-- Each report captures a point-in-time compliance score, control
-- statuses, and an evidence pack in JSONB.

CREATE TABLE IF NOT EXISTS compliance_reports (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id       UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    framework       TEXT NOT NULL CHECK (framework IN ('PCI_DSS', 'HIPAA', 'SOC2', 'ISO_27001')),
    score           DOUBLE PRECISION NOT NULL DEFAULT 0,
    max_score       DOUBLE PRECISION NOT NULL DEFAULT 0,
    controls        JSONB NOT NULL DEFAULT '[]'::jsonb,
    evidence_pack   JSONB NOT NULL DEFAULT '{}'::jsonb,
    generated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_compliance_reports_tenant ON compliance_reports(tenant_id);
CREATE INDEX idx_compliance_reports_tenant_framework ON compliance_reports(tenant_id, framework);

ALTER TABLE compliance_reports ENABLE ROW LEVEL SECURITY;
ALTER TABLE compliance_reports FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON compliance_reports
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

-- ===========================================================================
-- 023_playbooks.up.sql
-- ===========================================================================
-- 023_playbooks — Playbook definitions table.
--
-- Each playbook defines a trigger condition and an ordered set of
-- response steps. Steps are stored as JSONB array so the schema
-- is flexible across step types.

CREATE TABLE IF NOT EXISTS playbooks (
    id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id         UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    name              TEXT NOT NULL,
    description       TEXT NOT NULL DEFAULT '',
    trigger_condition TEXT NOT NULL DEFAULT '',
    steps             JSONB NOT NULL DEFAULT '[]'::jsonb,
    enabled           BOOLEAN NOT NULL DEFAULT true,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT playbooks_name_tenant_unique UNIQUE (tenant_id, name)
);

CREATE INDEX idx_playbooks_tenant ON playbooks(tenant_id);
CREATE INDEX idx_playbooks_tenant_enabled ON playbooks(tenant_id, enabled);

ALTER TABLE playbooks ENABLE ROW LEVEL SECURITY;
ALTER TABLE playbooks FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON playbooks
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

-- ===========================================================================
-- 024_playbook_executions.up.sql
-- ===========================================================================
-- 024_playbook_executions — Execution tracking for playbook runs.
--
-- playbook_executions tracks each invocation of a playbook.
-- playbook_step_results stores per-step outcomes within an execution.

CREATE TABLE IF NOT EXISTS playbook_executions (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id       UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    playbook_id     UUID NOT NULL REFERENCES playbooks(id) ON DELETE CASCADE,
    status          TEXT NOT NULL DEFAULT 'pending'
                    CHECK (status IN ('pending', 'running', 'completed', 'failed', 'rolled_back', 'awaiting_approval')),
    trigger_event   JSONB NOT NULL DEFAULT '{}'::jsonb,
    started_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    completed_at    TIMESTAMPTZ,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_playbook_executions_tenant ON playbook_executions(tenant_id);
CREATE INDEX idx_playbook_executions_playbook ON playbook_executions(tenant_id, playbook_id);

ALTER TABLE playbook_executions ENABLE ROW LEVEL SECURITY;
ALTER TABLE playbook_executions FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON playbook_executions
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

CREATE TABLE IF NOT EXISTS playbook_step_results (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    execution_id    UUID NOT NULL REFERENCES playbook_executions(id) ON DELETE CASCADE,
    tenant_id       UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    step_order      INTEGER NOT NULL,
    status          TEXT NOT NULL DEFAULT 'pending'
                    CHECK (status IN ('pending', 'running', 'completed', 'failed', 'skipped')),
    output          JSONB NOT NULL DEFAULT '{}'::jsonb,
    error           TEXT NOT NULL DEFAULT '',
    started_at      TIMESTAMPTZ,
    completed_at    TIMESTAMPTZ,

    CONSTRAINT step_results_exec_order_unique UNIQUE (execution_id, step_order)
);

CREATE INDEX idx_step_results_execution ON playbook_step_results(execution_id);

ALTER TABLE playbook_step_results ENABLE ROW LEVEL SECURITY;
ALTER TABLE playbook_step_results FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON playbook_step_results
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

-- ===========================================================================
-- 025_playbook_approvals.up.sql
-- ===========================================================================
-- 025_playbook_approvals — Approval workflow for playbook executions.
--
-- Tracks pending/approved/rejected/expired approvals for playbook
-- executions that require operator sign-off before proceeding.

CREATE TABLE IF NOT EXISTS playbook_approvals (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id       UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    execution_id    UUID NOT NULL REFERENCES playbook_executions(id) ON DELETE CASCADE,
    approver_id     UUID REFERENCES users(id) ON DELETE SET NULL,
    status          TEXT NOT NULL DEFAULT 'pending'
                    CHECK (status IN ('pending', 'approved', 'rejected', 'expired')),
    expires_at      TIMESTAMPTZ NOT NULL,
    decided_at      TIMESTAMPTZ,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_playbook_approvals_tenant ON playbook_approvals(tenant_id);
CREATE INDEX idx_playbook_approvals_pending ON playbook_approvals(tenant_id, status)
    WHERE status = 'pending';
CREATE INDEX idx_playbook_approvals_execution ON playbook_approvals(execution_id);

ALTER TABLE playbook_approvals ENABLE ROW LEVEL SECURITY;
ALTER TABLE playbook_approvals FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON playbook_approvals
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    )
    WITH CHECK (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    );

-- ===========================================================================
-- 026_ai_suggestions.up.sql
-- ===========================================================================
-- 026_ai_suggestions — AI policy tightening suggestions.
--
-- Stores AI-generated policy change suggestions with full review
-- workflow state. Each suggestion targets a specific rule and goes
-- through: pending -> approved/rejected -> (if approved) applied/rolled_back.
--
-- RLS: tenant_isolation on tenant_id, matching every other
-- tenant-scoped table in the control plane.

CREATE TABLE IF NOT EXISTS ai_policy_suggestions (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id       UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    rule_id         TEXT NOT NULL,
    category        TEXT NOT NULL,
    suggestion_json JSONB NOT NULL DEFAULT '{}',
    confidence      DOUBLE PRECISION NOT NULL DEFAULT 0,
    status          TEXT NOT NULL DEFAULT 'pending',
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    reviewed_at     TIMESTAMPTZ,
    reviewer_id     UUID REFERENCES users(id) ON DELETE SET NULL,
    feedback        TEXT,

    CONSTRAINT ai_policy_suggestions_category_check
        CHECK (category IN ('unused', 'shadowed', 'overly_permissive', 'deny_log')),
    CONSTRAINT ai_policy_suggestions_status_check
        CHECK (status IN ('pending', 'approved', 'rejected', 'applied', 'rolled_back')),
    CONSTRAINT ai_policy_suggestions_confidence_check
        CHECK (confidence >= 0 AND confidence <= 1)
);

CREATE INDEX IF NOT EXISTS ai_policy_suggestions_tenant_idx
    ON ai_policy_suggestions (tenant_id, created_at DESC, id DESC);

CREATE INDEX IF NOT EXISTS ai_policy_suggestions_status_idx
    ON ai_policy_suggestions (tenant_id, status)
    WHERE status = 'pending';

ALTER TABLE ai_policy_suggestions ENABLE ROW LEVEL SECURITY;
ALTER TABLE ai_policy_suggestions FORCE ROW LEVEL SECURITY;

CREATE POLICY tenant_isolation ON ai_policy_suggestions
    USING (tenant_id = current_setting('sng.tenant_id')::uuid);

