-- ===========================================================================
-- 034_idp_configs.up.sql
-- ===========================================================================
-- Migration 034: Per-tenant OIDC identity-provider configurations for
-- mobile native SSO (control-plane IdP federation). Each row describes
-- one OIDC provider a tenant trusts (Google Workspace, Microsoft 365,
-- Zoho, Okta, or a generic custom OIDC issuer). The control plane
-- validates mobile-presented ID tokens against the matching config and
-- mints an SNG session bound to device + user identity.
--
-- Only the configuration needed to *validate* tokens is persisted
-- (issuer, client_id, allowed domains, group-claim path). OIDC tokens
-- themselves are never stored server-side.

CREATE TABLE idp_configs (
    id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id        UUID        NOT NULL REFERENCES tenants(id),
    provider_type    TEXT        NOT NULL CHECK (provider_type IN (
                                     'google_workspace',
                                     'microsoft365',
                                     'zoho',
                                     'okta',
                                     'custom_oidc'
                                 )),
    issuer_url       TEXT        NOT NULL,
    client_id        TEXT        NOT NULL,
    allowed_domains  TEXT[]      NOT NULL DEFAULT '{}',
    group_claim_path TEXT        NOT NULL DEFAULT '',
    enabled          BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at       TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE idp_configs ENABLE ROW LEVEL SECURITY;

-- Tenant-scoped policy: a request bound to sng.tenant_id sees only
-- its own provider configs. Mirrors every other tenant-scoped table.
CREATE POLICY idp_configs_tenant ON idp_configs
    USING (tenant_id::text = current_setting('sng.tenant_id', true))
    WITH CHECK (tenant_id::text = current_setting('sng.tenant_id', true));

-- System policy: background workers / cross-tenant jobs that set
-- sng.system_role='true' may read/write across tenants.
CREATE POLICY idp_configs_system ON idp_configs
    USING (current_setting('sng.system_role', true) = 'true')
    WITH CHECK (current_setting('sng.system_role', true) = 'true');

-- One provider config per (tenant, issuer): a tenant cannot register
-- the same OIDC issuer twice, which would make token-to-config
-- resolution ambiguous.
CREATE UNIQUE INDEX uq_idp_configs_tenant_issuer
    ON idp_configs (tenant_id, issuer_url);

CREATE INDEX idx_idp_configs_tenant
    ON idp_configs (tenant_id, created_at DESC);

-- ===========================================================================
-- 035_site_ha.up.sql
-- ===========================================================================
-- 035_site_ha — Active/passive HA posture for site edge appliances.
--
-- Adds the control-plane side of Session C's edge HA feature: a
-- site can run a single edge VM (standalone, the default) or a
-- VRRP-class active/passive pair that fails the site VIP over
-- between two edge devices. The enforcement-plane half lives in
-- the `sng-ha` crate (wired into `sng-edge`); these columns let
-- the control plane record the operator's intent and the partner
-- device so dashboards / Terraform / the API can reason about a
-- site's failover topology.
--
--   * ha_mode            — 'standalone' | 'active_passive'. CHECK
--                          constraint mirrors `SiteHAMode` in
--                          internal/repository/types.go. Backfilled
--                          to 'standalone' for every existing site
--                          via the NOT NULL DEFAULT, so the column
--                          is safe to add to a populated table.
--   * ha_peer_device_id  — nullable FK onto devices(id), the
--                          partner edge in an active/passive pair.
--                          ON DELETE SET NULL: de-enrolling the
--                          peer device must not cascade-delete the
--                          site; it simply drops the pairing and
--                          the operator re-pairs a replacement.
--
-- RLS: `sites` already has tenant-isolation ROW LEVEL SECURITY
-- enabled in migration 001 (policy `sites_tenant_isolation` keyed
-- on the `sng.tenant_id` GUC). Adding columns to an existing
-- RLS-protected table inherits that policy, so no new policy is
-- required here.
ALTER TABLE sites
    ADD COLUMN IF NOT EXISTS ha_mode TEXT NOT NULL DEFAULT 'standalone'
        CHECK (ha_mode IN ('standalone', 'active_passive'));

ALTER TABLE sites
    ADD COLUMN IF NOT EXISTS ha_peer_device_id UUID REFERENCES devices(id) ON DELETE SET NULL;

-- Partial index on the partner FK: failover-topology lookups and
-- the integrity sweep that checks "is any site paired to this
-- device?" only ever care about rows that actually have a peer.
CREATE INDEX IF NOT EXISTS sites_ha_peer_device_idx
    ON sites (ha_peer_device_id)
    WHERE ha_peer_device_id IS NOT NULL;

-- ===========================================================================
-- 036_sdwan_sla.up.sql
-- ===========================================================================
-- Migration 036: Per-tenant SD-WAN SLA policy templates. Each row is
-- a named set of path-quality thresholds (latency, loss, jitter,
-- throughput) for one SLA traffic class. The control plane CRUDs these
-- templates and compiles the active set into the SD-WAN slice of the
-- signed policy bundle; the `sng-sdwan` enforcement plane evaluates
-- live probe results against the compiled thresholds, raising
-- sustained-breach violations that drive automatic failover.
--
-- The default template set every tenant starts with:
--   business-critical  latency < 50 ms, loss < 0.1 %
--   real-time          jitter < 15 ms
--   best-effort        no SLA (all thresholds NULL)
--
-- A NULL threshold means "this metric does not gate the SLA"; an
-- all-NULL row (best-effort) therefore never reports a violation.

CREATE TABLE sdwan_sla_policies (
    id                  UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id           UUID        NOT NULL REFERENCES tenants(id),
    name                TEXT        NOT NULL,
    traffic_class       TEXT        NOT NULL CHECK (traffic_class IN (
                                        'business-critical',
                                        'real-time',
                                        'best-effort'
                                    )),
    max_latency_ms      DOUBLE PRECISION CHECK (max_latency_ms IS NULL OR max_latency_ms >= 0),
    max_loss_pct        DOUBLE PRECISION CHECK (max_loss_pct IS NULL OR (max_loss_pct >= 0 AND max_loss_pct <= 100)),
    max_jitter_ms       DOUBLE PRECISION CHECK (max_jitter_ms IS NULL OR max_jitter_ms >= 0),
    min_throughput_mbps DOUBLE PRECISION CHECK (min_throughput_mbps IS NULL OR min_throughput_mbps >= 0),
    created_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE sdwan_sla_policies ENABLE ROW LEVEL SECURITY;

-- Tenant-scoped policy: a request bound to sng.tenant_id sees only
-- its own SLA templates. Mirrors every other tenant-scoped table.
CREATE POLICY sdwan_sla_policies_tenant ON sdwan_sla_policies
    USING (tenant_id::text = current_setting('sng.tenant_id', true))
    WITH CHECK (tenant_id::text = current_setting('sng.tenant_id', true));

-- System policy: background workers / cross-tenant jobs that set
-- sng.system_role='true' may read/write across tenants.
CREATE POLICY sdwan_sla_policies_system ON sdwan_sla_policies
    USING (current_setting('sng.system_role', true) = 'true')
    WITH CHECK (current_setting('sng.system_role', true) = 'true');

-- One template name per tenant: the name is the operator-facing
-- handle used to address a template, so it must be unique within a
-- tenant.
CREATE UNIQUE INDEX uq_sdwan_sla_policies_tenant_name
    ON sdwan_sla_policies (tenant_id, name);

CREATE INDEX idx_sdwan_sla_policies_tenant
    ON sdwan_sla_policies (tenant_id, created_at DESC);

-- ===========================================================================
-- 037_inline_casb.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — Inline CASB migration.
--
-- Upgrades API-mode CASB (migration 016) to inline, real-time
-- inspection in the SWG ext-authz path. This table holds the
-- per-tenant inline-CASB rules the control plane manages
-- (internal/service/casb/inline.go) and compiles into the SWG
-- slice of the signed policy bundle; the edge / cloud data plane
-- (crates/sng-swg/src/casb.rs) decodes that slice and enforces it
-- on live SaaS traffic (M365, Google Workspace, Slack, Salesforce).
--
-- Adds one table:
--   - inline_casb_rules : per-tenant inline-CASB rules.
--
-- RLS-scoped to `sng.tenant_id`, matching every other
-- tenant-scoped table.

CREATE TABLE IF NOT EXISTS inline_casb_rules (
    id          UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id   UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    -- SaaS app id the rule applies to: one of the inspector's
    -- detected apps ('m365', 'google_workspace', 'slack',
    -- 'salesforce') or '*' for any app. Kept as free TEXT rather
    -- than a CHECK so new apps in the data-plane catalog do not
    -- require a schema migration; the service layer validates the
    -- value against the known-app set.
    app_id      TEXT        NOT NULL,
    action      TEXT        NOT NULL
                CHECK (action IN ('upload', 'download', 'share', 'delete')),
    verdict     TEXT        NOT NULL DEFAULT 'log'
                CHECK (verdict IN ('allow', 'block', 'log')),
    -- Match conditions: {file_type, size_threshold, label_match}.
    -- Shape mirrors the Rust CasbConditions; an empty object means
    -- "match every request for this (app_id, action)".
    conditions  JSONB       NOT NULL DEFAULT '{}'::jsonb,
    enabled     BOOLEAN     NOT NULL DEFAULT TRUE,
    -- Higher priority wins when several rules match a request.
    priority    INTEGER     NOT NULL DEFAULT 0,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Hot-path index: "list all enabled rules for a tenant" (the
-- compile path reads only enabled rules), highest priority first.
CREATE INDEX IF NOT EXISTS idx_inline_casb_rules_tenant_enabled
    ON inline_casb_rules (tenant_id, priority DESC) WHERE enabled = TRUE;
CREATE INDEX IF NOT EXISTS idx_inline_casb_rules_tenant
    ON inline_casb_rules (tenant_id);
CREATE INDEX IF NOT EXISTS idx_inline_casb_rules_tenant_app_action
    ON inline_casb_rules (tenant_id, app_id, action);

CREATE TRIGGER inline_casb_rules_set_updated_at
    BEFORE UPDATE ON inline_casb_rules
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE inline_casb_rules ENABLE ROW LEVEL SECURITY;
ALTER TABLE inline_casb_rules FORCE ROW LEVEL SECURITY;

CREATE POLICY inline_casb_rules_tenant_isolation ON inline_casb_rules
    USING (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid)
    WITH CHECK (tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid);

-- ===========================================================================
-- 038_pops.up.sql
-- ===========================================================================
-- Migration 038: Cloud PoP (Point-of-Presence) service. Backs
-- Session F's cloud-delivered SWG/DNS/ZTNA edge for tenants without
-- an on-premise edge VM.
--
-- A PoP is a shared, multi-tenant deployment of the `sng-edge`
-- binary running in a cloud region. The control plane keeps a
-- registry of PoP locations, ingests their health beacons, and
-- routes cloud-only tenants to their nearest healthy PoP. Three
-- tables model that:
--
--   * pops                    — GLOBAL registry of PoP locations.
--                               A PoP is shared infrastructure, not
--                               owned by any one tenant, so it has
--                               NO tenant_id and NO RLS (mirrors the
--                               `tenants` table in migration 001,
--                               which is likewise un-scoped). The
--                               public `GET /api/v1/pops` bootstrap
--                               endpoint reads this table.
--   * pop_health              — append-only time-series of health
--                               beacons (one row per heartbeat).
--                               Also global: it describes shared
--                               infrastructure, not tenant data, so
--                               no RLS. Cross-tenant flow data NEVER
--                               lands here — only PoP-level resource
--                               counters.
--   * tenant_pop_assignments  — which PoP serves each cloud-only
--                               tenant. This IS tenant data, so it
--                               carries tenant_id and is RLS-scoped
--                               on the `sng.tenant_id` GUC exactly
--                               like every other tenant-scoped
--                               table (see migration 036).

-- ---------------------------------------------------------------------
-- pops — global PoP registry.
--
-- provider / capacity_tier are constrained to the closed sets the
-- control plane + edge understand. anycast_ip is the address clients
-- steer to (returned by the GeoDNS zone); dns_name is the per-PoP
-- hostname operators can target directly. `enabled` gates a PoP out
-- of auto-assignment without deleting its history.
-- ---------------------------------------------------------------------
CREATE TABLE pops (
    id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    region        TEXT        NOT NULL,
    provider      TEXT        NOT NULL CHECK (provider IN ('aws', 'gcp', 'azure')),
    anycast_ip    INET        NOT NULL,
    dns_name      TEXT        NOT NULL,
    capacity_tier TEXT        NOT NULL CHECK (capacity_tier IN ('small', 'medium', 'large')),
    enabled       BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- One PoP per region+provider pair: the operator addresses a PoP by
-- "the aws us-east-1 PoP", so that tuple must be unique.
CREATE UNIQUE INDEX uq_pops_region_provider ON pops (region, provider);

-- dns_name is the externally-resolvable handle clients enrol against;
-- it must be globally unique across the fleet.
CREATE UNIQUE INDEX uq_pops_dns_name ON pops (dns_name);

-- Hot path for AssignPoP / the public bootstrap list: only enabled
-- PoPs are candidates, so index them partially.
CREATE INDEX idx_pops_enabled ON pops (region) WHERE enabled;

CREATE TRIGGER pops_set_updated_at
    BEFORE UPDATE ON pops
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

-- ---------------------------------------------------------------------
-- pop_health — append-only health beacons.
--
-- Health updates arrive over NATS (`sng.pop.{pop_id}.health`) and the
-- control plane persists each beacon so the admin health view and the
-- assignment logic can reason about recent load. Global (no RLS): the
-- counters describe shared infra capacity, never tenant traffic.
-- ON DELETE CASCADE so de-provisioning a PoP removes its history.
-- ---------------------------------------------------------------------
CREATE TABLE pop_health (
    pop_id             UUID        NOT NULL REFERENCES pops(id) ON DELETE CASCADE,
    reported_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
    cpu_pct            REAL        NOT NULL CHECK (cpu_pct >= 0 AND cpu_pct <= 100),
    memory_pct         REAL        NOT NULL CHECK (memory_pct >= 0 AND memory_pct <= 100),
    active_connections INTEGER     NOT NULL CHECK (active_connections >= 0),
    bandwidth_mbps     REAL        NOT NULL CHECK (bandwidth_mbps >= 0),
    PRIMARY KEY (pop_id, reported_at)
);

-- Latest-beacon-per-PoP lookups order by reported_at descending.
CREATE INDEX idx_pop_health_pop_reported ON pop_health (pop_id, reported_at DESC);

-- ---------------------------------------------------------------------
-- tenant_pop_assignments — which PoP serves a cloud-only tenant.
--
-- Exactly one assignment per tenant (PRIMARY KEY on tenant_id): a
-- tenant is steered to a single home PoP at a time. `override` marks
-- an operator-pinned assignment so the auto-rebalancer leaves it
-- alone. Tenant-scoped → RLS on sng.tenant_id, with the standard
-- system-role escape hatch for cross-tenant background jobs (the
-- rebalancer), mirroring migration 036.
-- ---------------------------------------------------------------------
CREATE TABLE tenant_pop_assignments (
    tenant_id   UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    pop_id      UUID        NOT NULL REFERENCES pops(id) ON DELETE CASCADE,
    assigned_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    override    BOOLEAN     NOT NULL DEFAULT FALSE,
    PRIMARY KEY (tenant_id)
);

-- Reverse lookup: "which tenants does this PoP serve?" — used by the
-- capacity rebalancer when a PoP signals it is overloaded.
CREATE INDEX idx_tenant_pop_assignments_pop ON tenant_pop_assignments (pop_id);

-- ENABLE applies RLS to the runtime app role; FORCE extends it to
-- the table owner too, so even a connection using the migration /
-- owner credentials cannot bypass tenant isolation. Both are the
-- documented standard for tenant-scoped tables (see migration 002
-- and 037_inline_casb).
ALTER TABLE tenant_pop_assignments ENABLE ROW LEVEL SECURITY;
ALTER TABLE tenant_pop_assignments FORCE ROW LEVEL SECURITY;

-- Tenant-scoped policy: a request bound to sng.tenant_id sees only
-- its own assignment. Mirrors every other tenant-scoped table.
CREATE POLICY tenant_pop_assignments_tenant ON tenant_pop_assignments
    USING (tenant_id::text = current_setting('sng.tenant_id', true))
    WITH CHECK (tenant_id::text = current_setting('sng.tenant_id', true));

-- System policy: background workers / cross-tenant jobs (the
-- capacity rebalancer, the auto-assigner) that set
-- sng.system_role='true' may read/write across tenants.
CREATE POLICY tenant_pop_assignments_system ON tenant_pop_assignments
    USING (current_setting('sng.system_role', true) = 'true')
    WITH CHECK (current_setting('sng.system_role', true) = 'true');

-- ===========================================================================
-- 039_compliance_evidence.up.sql
-- ===========================================================================
-- Migration 039: SOC2 Type II compliance evidence automation.
--
-- Adds the platform-level `compliance_evidence` table that tracks the
-- signed evidence bundles the SOC2 evidence collector produces
-- (internal/service/compliance/{soc2,evidence,scheduler}.go).
--
-- PLATFORM-LEVEL, NOT tenant-scoped: SOC2 Type II evidence attests to
-- the SNG *platform's own* controls (RBAC config, audit trail,
-- monitoring, availability), not any single tenant's data. There is
-- therefore no tenant_id column and deliberately NO row-level
-- security — the rows are only ever read/written by the platform
-- admin surface and the leader-only collector running under the
-- system role. Compare with `compliance_reports` (migration 023),
-- which IS per-tenant and RLS-scoped.
--
-- Each row records where the bundle lives (s3_key), when it was
-- collected (collected_at), and the Ed25519 signature over the bundle
-- bytes (signature, hex-encoded) so a verifier can prove the archived
-- bundle has not been tampered with. The bundle bytes themselves live
-- in S3 under a 7-year compliance-retention policy; this table is the
-- queryable index over them.

CREATE TABLE compliance_evidence (
    id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    -- collection_type distinguishes the scheduler-driven weekly
    -- collections, the monthly audit-ready aggregations, and
    -- operator-triggered manual runs.
    collection_type TEXT        NOT NULL
        CONSTRAINT compliance_evidence_collection_type_chk
            CHECK (collection_type IN ('weekly', 'monthly', 'manual')),
    collected_at    TIMESTAMPTZ NOT NULL,
    -- s3_key is the object key the signed bundle was written to. It is
    -- unique: one stored object per evidence row.
    s3_key          TEXT        NOT NULL
        CONSTRAINT compliance_evidence_s3_key_unique UNIQUE,
    -- signature is the hex-encoded Ed25519 signature over the
    -- canonical bundle bytes.
    signature       TEXT        NOT NULL,
    status          TEXT        NOT NULL DEFAULT 'collected'
        CONSTRAINT compliance_evidence_status_chk
            CHECK (status IN ('collecting', 'collected', 'failed', 'aggregated')),
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- The list endpoint and the scheduler's gap-detection query both order
-- by collected_at DESC; index the sort key. A second composite index
-- supports "most recent collection of type X" lookups used by gap
-- detection and monthly aggregation.
CREATE INDEX idx_compliance_evidence_collected_at
    ON compliance_evidence (collected_at DESC);

CREATE INDEX idx_compliance_evidence_type_collected_at
    ON compliance_evidence (collection_type, collected_at DESC);

-- ===========================================================================
-- 040_metering.up.sql
-- ===========================================================================
-- ShieldNet Gateway (SNG) — Cost Metering & Budget Guardrails.
--
-- Session K. Models per-tenant resource consumption (LLM inference,
-- URL-categorisation / malware feed lookups, telemetry write
-- amplification, archive + proxied bandwidth) and the per-tenant
-- budget limits that gate it.
--
-- The control-plane metering service
-- (internal/service/metering/service.go) keeps `sync/atomic`
-- counters on the hot path and flushes accumulated deltas into
-- `tenant_usage` every 60s via a single batch upsert; the
-- BudgetEnforcer (internal/service/metering/budget.go) reads
-- `tenant_budgets` to decide whether an operation is within its
-- soft / hard limit.
--
-- Adds two tables:
--   - tenant_usage   : per-tenant, per-meter consumption bucketed
--                      by billing period (one row per
--                      tenant+meter+period_start).
--   - tenant_budgets : per-tenant soft / hard limit overrides per
--                      meter. Tier defaults live in application
--                      config; only explicit overrides are stored.
--
-- Both are RLS-scoped to `sng.tenant_id`, matching every other
-- tenant-scoped table, with a `sng.system_role='true'` bypass so
-- the cross-tenant flush worker and the MSP/admin platform-wide
-- cost report can read / write every tenant's rows. The system
-- role is a GUC the application sets only on background / admin
-- transactions — it is not a DB role grant, so per-request
-- handlers remain strictly tenant-isolated.

CREATE TABLE IF NOT EXISTS tenant_usage (
    id           UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id    UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    -- Canonical meter name, e.g. 'llm_tokens_used', 'llm_calls',
    -- 'url_cat_lookups', 'malware_scans', 'clickhouse_rows_written',
    -- 's3_bytes_archived', 'bandwidth_proxied_bytes'. Kept as free
    -- TEXT (not a CHECK enum) so new meters do not require a schema
    -- migration; the service layer validates against the known-meter
    -- set in internal/service/metering.
    meter        TEXT        NOT NULL,
    -- Inclusive period_start / exclusive period_end bounds for the
    -- billing bucket this row accumulates. Daily meters use a
    -- one-day window; monthly meters use a calendar-month window.
    period_start DATE        NOT NULL,
    period_end   DATE        NOT NULL,
    -- Monotonic accumulated consumption for the period. bigint so a
    -- high-volume meter (bandwidth bytes) cannot overflow.
    value        BIGINT      NOT NULL DEFAULT 0 CHECK (value >= 0),
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    -- One row per (tenant, meter, period). The flush worker relies
    -- on this to upsert deltas with
    -- `ON CONFLICT (tenant_id, meter, period_start) DO UPDATE
    --  SET value = tenant_usage.value + EXCLUDED.value`.
    CONSTRAINT tenant_usage_unique_period UNIQUE (tenant_id, meter, period_start)
);

-- Hot-path read: "current-period usage for a tenant" and the
-- monthly-history aggregation both scan by tenant then period.
CREATE INDEX IF NOT EXISTS idx_tenant_usage_tenant_period
    ON tenant_usage (tenant_id, period_start DESC);
-- Platform-wide cost report aggregates every tenant's rows for a
-- period; index the period so the cross-tenant scan is bounded.
CREATE INDEX IF NOT EXISTS idx_tenant_usage_period
    ON tenant_usage (period_start, meter);

CREATE TRIGGER tenant_usage_set_updated_at
    BEFORE UPDATE ON tenant_usage
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE tenant_usage ENABLE ROW LEVEL SECURITY;
ALTER TABLE tenant_usage FORCE ROW LEVEL SECURITY;

CREATE POLICY tenant_usage_tenant_isolation ON tenant_usage
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    )
    WITH CHECK (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    );

CREATE TABLE IF NOT EXISTS tenant_budgets (
    id          UUID        PRIMARY KEY DEFAULT uuid_generate_v4(),
    tenant_id   UUID        NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    meter       TEXT        NOT NULL,
    -- soft_limit: log + alert when exceeded but allow the operation.
    -- hard_limit: reject the operation (429 budget_exceeded). A NULL
    -- or non-positive value means "unbounded" for that side, letting
    -- an operator set only a soft alert without a hard cap.
    soft_limit  BIGINT      NOT NULL DEFAULT 0 CHECK (soft_limit >= 0),
    hard_limit  BIGINT      NOT NULL DEFAULT 0 CHECK (hard_limit >= 0),
    -- Budget reset cadence: 'daily' or 'monthly'.
    period      TEXT        NOT NULL DEFAULT 'monthly'
                CHECK (period IN ('daily', 'monthly')),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT tenant_budgets_unique_meter UNIQUE (tenant_id, meter)
);

CREATE INDEX IF NOT EXISTS idx_tenant_budgets_tenant
    ON tenant_budgets (tenant_id);

CREATE TRIGGER tenant_budgets_set_updated_at
    BEFORE UPDATE ON tenant_budgets
    FOR EACH ROW EXECUTE FUNCTION sng_set_updated_at();

ALTER TABLE tenant_budgets ENABLE ROW LEVEL SECURITY;
ALTER TABLE tenant_budgets FORCE ROW LEVEL SECURITY;

CREATE POLICY tenant_budgets_tenant_isolation ON tenant_budgets
    USING (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    )
    WITH CHECK (
        tenant_id = NULLIF(current_setting('sng.tenant_id', true), '')::uuid
        OR NULLIF(current_setting('sng.system_role', true), '') = 'true'
    );

-- ===========================================================================
-- 041_devices_pubkey_unique.up.sql
-- ===========================================================================
-- Migration 041: enforce that an Ed25519 device public key is unique
-- within a tenant.
--
-- Why: the mobile self-enrolment flow
-- (POST /tenants/{tenant_id}/devices/mobile/enroll) is idempotent —
-- re-enrolling the same device_key for a tenant must UPDATE the
-- existing device rather than create a duplicate. The service resolves
-- the existing device via DeviceRepository.GetByPublicKey before
-- deciding create-vs-update, but a lookup-then-create is racy on its
-- own: two concurrent first-enrolments of the same key could both miss
-- the lookup and both insert. This partial unique index closes that
-- race at the database level — the second INSERT fails with a unique
-- violation (surfaced as repository.ErrConflict), and the service
-- falls back to the update path. A device public key identifies
-- exactly one device, so this is the correct invariant regardless of
-- enrolment path (it also hardens the existing claim-token flow).
--
-- The index is PARTIAL (WHERE public_key_ed25519 IS NOT NULL) because
-- the column is nullable and the create path stores NULLIF(key, '')
-- — devices enrolled without a key (e.g. bulk CSV inventory imports)
-- leave it NULL, and Postgres treats multiple NULLs as distinct, so
-- those rows are never constrained against each other.
--
-- CONCURRENTLY is intentionally NOT used: golang-migrate wraps each
-- migration in a transaction and CREATE INDEX CONCURRENTLY cannot run
-- inside one. The devices table is small relative to a brief build-time
-- lock, and every other index in this schema is created non-concurrently.
CREATE UNIQUE INDEX IF NOT EXISTS uq_devices_tenant_public_key
    ON devices (tenant_id, public_key_ed25519)
    WHERE public_key_ed25519 IS NOT NULL;

